  // ── /api/agent/conversations/search ──────────────────────────────────────
  if (path === '/api/agent/conversations/search' && method === 'GET') {
    if (!env.DB) return jsonResponse([]);
    const q = (url.searchParams.get('q') || '').trim();
    if (!q) return jsonResponse([]);
    const like = `%${q.replace(/%/g,'\\%').replace(/_/g,'\\_')}%`;
    const { results } = await env.DB.prepare(`SELECT id, COALESCE(name,title,'') as title FROM agent_conversations WHERE name LIKE ? ESCAPE '\\' OR title LIKE ? ESCAPE '\\' ORDER BY id DESC LIMIT 20`).bind(like,like).all().catch(() => ({ results: [] }));
    return jsonResponse((results||[]).map(r=>({ id: r.id, title: r.title||'New Conversation' })));
  }

  // ── /api/agent/sessions/:id/messages ─────────────────────────────────────
  const sessMessagesMatch = path.match(/^\/api\/agent\/sessions\/([^/]+)\/messages$/);
  if (sessMessagesMatch && method === 'GET') {
    const convId = decodeURIComponent(sessMessagesMatch[1] || '').trim();
    if (!convId) return jsonResponse({ error: 'session id required' }, 400);
    if (env.AGENT_SESSION) {
      try {
        const doId = env.AGENT_SESSION.idFromName(convId);
        const stub = env.AGENT_SESSION.get(doId);
        const lim  = url.searchParams.get('limit') || '100';
        const resp = await stub.fetch(new Request(`https://do/history?limit=${encodeURIComponent(lim)}`));
        const rows = await resp.json().catch(() => []);
        return jsonResponse(Array.isArray(rows) ? rows : (rows.messages || []));
      } catch (_) {}
    }
    if (!env.DB) return jsonResponse([]);
    const { results } = await env.DB.prepare(
      `SELECT role, content, created_at FROM agent_messages
       WHERE conversation_id = ? ORDER BY created_at ASC LIMIT 200`
    ).bind(convId).all().catch(() => ({ results: [] }));
    return jsonResponse(results || []);
  }

  // ── /api/agent/sessions PATCH /:id ───────────────────────────────────────
  const sessionPatchMatch = path.match(/^\/api\/agent\/sessions\/([^/]+)$/);
  if (sessionPatchMatch && method === 'PATCH') {
    const convId = sessionPatchMatch[1];
    const body   = await request.json().catch(() => ({}));
    if (!env.DB) return jsonResponse({ error: 'DB not configured' }, 503);
    await env.DB.prepare(`UPDATE mcp_agent_sessions SET status = ?, last_activity = ?, updated_at = unixepoch() WHERE conversation_id = ?`).bind(String(body.status||'completed'), new Date().toISOString(), convId).run().catch(() => {});
    return jsonResponse({ success: true });
  }

  // ── /api/agent/sessions ───────────────────────────────────────────────────
  if (path === '/api/agent/sessions') {
    if (!env.DB) return jsonResponse({ error: 'DB not configured' }, 503);
    const authUser = await getAuthUser(request, env);
    if (!authUser) return jsonResponse({ error: 'Unauthorized' }, 401);
    let tenantId =
      authUser.tenant_id != null && String(authUser.tenant_id).trim() !== ''
        ? String(authUser.tenant_id).trim()
        : null;
    if (!tenantId) tenantId = await fetchAuthUserTenantId(env, authUser.id);
    if (!tenantId && authUser.email) tenantId = await fetchAuthUserTenantId(env, authUser.email);
    if (!tenantId) return jsonResponse({ error: 'Tenant not configured for this account' }, 403);
    if (method === 'POST') {
      const body   = await request.json().catch(() => ({}));
      const id     = crypto.randomUUID();
      const now    = Math.floor(Date.now() / 1000);
      const name   = (typeof body.name === 'string' && body.name.trim()) ? body.name.trim() : 'New Conversation';
      const r2Key  = `agent-sessions/${id}/context.json`;
      const sessCtx = JSON.stringify({ session_id: id, name, created_at: Date.now(), message_count: 0, messages: [] });
      if (env.R2) await env.R2.put(r2Key, sessCtx, { httpMetadata: { contentType: 'application/json' } }).catch(() => {});
      if (env.SESSION_CACHE) await env.SESSION_CACHE.put(`sess_ctx:${id}`, sessCtx, { expirationTtl: 86400 }).catch(() => {});
      await env.DB.prepare(`INSERT INTO agent_sessions (id, tenant_id, name, session_type, status, state_json, r2_key, started_at, updated_at) VALUES (?,?,?,?,?,?,?,?,?)`).bind(id, tenantId, name, body.session_type||'chat', 'active', '{}', r2Key, now, now).run();
      return jsonResponse({ id, status: 'active' });
    }
    const { results } = await env.DB.prepare(`SELECT s.id, s.session_type, s.status, s.started_at, COALESCE(s.name,ac.name,ac.title,'New Conversation') as name, (SELECT COUNT(*) FROM agent_messages am WHERE am.conversation_id = s.id) as message_count FROM agent_sessions s LEFT JOIN agent_conversations ac ON ac.id = s.id WHERE s.tenant_id = ? ORDER BY s.updated_at DESC LIMIT 50`).bind(tenantId).all().catch(() => ({ results: [] }));
    return jsonResponse(results || []);
  }

  // ── /api/agent/workspace/:id ──────────────────────────────────────────────
  const workspaceMatch = path.match(/^\/api\/agent\/workspace\/([^/]+)$/);
  if (workspaceMatch) {
    const wsId = decodeURIComponent(workspaceMatch[1] || '').trim();
    if (!env.DB) return jsonResponse({ error: 'DB not configured' }, 503);
    const authUser = await getAuthUser(request, env);
    if (!authUser) return jsonResponse({ error: 'Unauthorized' }, 401);

    // ── /api/agent/workspace/:id ────────────────────────────────────────────
    // ── /api/agent/workspace/:id ────────────────────────────────────────────
    if (method === 'GET') {
      try {
        const userId = String(authUser?.id || 'anonymous').trim();
        let tid =
          authUser?.tenant_id != null && String(authUser.tenant_id).trim() !== ''
            ? String(authUser.tenant_id).trim()
            : '';
        if (!tid) tid = (await fetchAuthUserTenantId(env, authUser.id)) || '';
        if (!tid && authUser.email) tid = (await fetchAuthUserTenantId(env, authUser.email)) || '';
        if (!tid) return jsonResponse({ error: 'Tenant not configured for this account' }, 403);
        const uwsId  = `uws:${tid}:${userId}:${wsId}`;

        // Attempt retrieval from both tables
        const [globalWs, personalWs] = await Promise.all([
          env.DB.prepare(`SELECT * FROM workspaces WHERE id = ? OR handle = ? LIMIT 1`).bind(wsId, wsId).first().catch(() => null),
          env.DB.prepare(`SELECT state_json FROM agentsam_workspace_state WHERE id = ?`).bind(uwsId).first().catch(() => null)
        ]);

        const row = globalWs || (personalWs ? { id: wsId, state_json: personalWs.state_json, name: 'Personal' } : null);
        if (!row) return jsonResponse({ error: 'Workspace not found' }, 404);

        const safeJson = (v) => { 
          if (!v) return {}; 
          if (typeof v === 'object' && v !== null) return v;
          try { return JSON.parse(v); } catch(e) { return {}; }
        };

        const stateObj = safeJson(row.state_json);
        const stateJsonStr =
          typeof row.state_json === 'string' && row.state_json.trim()
            ? row.state_json
            : JSON.stringify(stateObj || {});

        return jsonResponse({
          id: row.id,
          name: row.name || 'Workspace',
          environment: row.environment || 'local',
          status: row.status || 'active',
          settings: safeJson(row.settings_json),
          state:    stateObj,
          state_json: stateJsonStr,
        });
      } catch (e) { 
        return jsonResponse({ error: `Fetch error: ${e.message}` }, 500); 
      }
    }

    if (method === 'PUT') {
      try {
        const body    = await request.json().catch(() => ({}));
        const state   = body.state || body.state_json;
        const stateStr = typeof state === 'string' ? state : JSON.stringify(state || {});

        const userId = String(authUser?.id || 'anonymous').trim();
        let tid =
          authUser?.tenant_id != null && String(authUser.tenant_id).trim() !== ''
            ? String(authUser.tenant_id).trim()
            : '';
        if (!tid) tid = (await fetchAuthUserTenantId(env, authUser.id)) || '';
        if (!tid && authUser.email) tid = (await fetchAuthUserTenantId(env, authUser.email)) || '';
        if (!tid) return jsonResponse({ error: 'Tenant not configured for this account' }, 403);
        const uwsId  = `uws:${tid}:${userId}:${wsId}`;

        // Attempt update in both locations (idempotent for the relevant table)
        try {
          if (env.DB) {
            const results = await Promise.allSettled([
              env.DB.prepare(`UPDATE workspaces SET state_json = ?, updated_at = datetime('now') WHERE id = ?`)
                .bind(stateStr, wsId).run(),
              env.DB.prepare(`UPDATE agentsam_workspace_state SET state_json = ?, updated_at = unixepoch() WHERE id = ?`)
                .bind(stateStr, uwsId).run()
            ]);
            results.forEach((r, i) => {
              if (r.status === 'rejected') {
                console.warn('[agent] workspace update op', i, 'rejected:', r.reason);
              }
            });
            console.log('[agent] workspace update results:', results.map(r => r.status));
          }
        } catch (dbErr) {
          console.warn('[agent] non-critical workspace update failure:', dbErr.message);
        }

        return jsonResponse({ ok: true, id: wsId });
      } catch (e) { 
        console.error('[agent] workspace PUT error:', e.stack);
        return jsonResponse({ error: e.message }, 500); 
      }
    }

    if (method === 'POST') {
      const defaultWs =
        env?.DEFAULT_WORKSPACE_ID != null && String(env.DEFAULT_WORKSPACE_ID).trim() !== ''
          ? String(env.DEFAULT_WORKSPACE_ID).trim()
          : '';
      const isAgentsamWs = /^ws_/i.test(wsId) || (defaultWs !== '' && wsId === defaultWs);
      if (!isAgentsamWs) {
        return jsonResponse(
          { error: 'Use PUT for conversation workspace snapshots; POST merge is for ws_* workspace ids.' },
          400,
        );
      }
      try {
        const bodyPost = await request.json().catch(() => ({}));
        if (!bodyPost || typeof bodyPost !== 'object') return jsonResponse({ error: 'Invalid JSON' }, 400);
        let awsRow = null;
        try {
          awsRow = await env.DB.prepare(
            `SELECT id, state_json FROM agentsam_workspace_state WHERE workspace_id = ? OR id = ? ORDER BY updated_at DESC LIMIT 1`,
          )
            .bind(wsId, wsId)
            .first();
        } catch (_) {
          awsRow = null;
        }
        const safeJsonState = (v) => {
          if (!v) return {};
          if (typeof v === 'object' && v !== null) return v;
          try { return JSON.parse(String(v)); } catch { return {}; }
        };
        const stringifyState = (state) => (typeof state === 'string' ? state : JSON.stringify(state || {}));
        const cur = safeJsonState(awsRow?.state_json);
        const patch = {};
        for (const k of ['active_agent_slug', 'active_agent_panel', 'last_agent_action', 'agent_id']) {
          if (Object.prototype.hasOwnProperty.call(bodyPost, k) && bodyPost[k] != null) patch[k] = bodyPost[k];
        }
        const merged = { ...cur, ...patch };
        const mergedStr = stringifyState(merged);
        if (awsRow?.id) {
          await env.DB.prepare(
            `UPDATE agentsam_workspace_state SET state_json = ?, updated_at = unixepoch() WHERE id = ?`,
          )
            .bind(mergedStr, awsRow.id)
            .run();
        } else {
          const nid = `aws_${crypto.randomUUID().replace(/-/g, '').slice(0, 16)}`;
          try {
            await env.DB.prepare(
              `INSERT INTO agentsam_workspace_state (id, workspace_id, state_json, updated_at) VALUES (?,?,?,unixepoch())`,
            )
              .bind(nid, wsId, mergedStr)
              .run();
          } catch (e3) {
            console.warn('[agent/workspace] agentsam POST insert', e3?.message ?? e3);
            return jsonResponse({ error: 'agentsam_workspace_state write failed' }, 503);
          }
        }
        return jsonResponse({ ok: true, id: wsId });
      } catch (e) {
        return jsonResponse({ error: e.message }, 500);
      }
    }
  }

  // ── /api/agent/terminal/config-status ────────────────────────────────────
  if (path === '/api/agent/terminal/config-status' && method === 'GET') {
    const authUser = await getAuthUser(request, env);
    if (!authUser) return jsonResponse({ error: 'Unauthorized' }, 401);
    if (!authUserIsSuperadmin(authUser)) {
      return jsonResponse({
        terminal_enabled: false,
        terminal_configured: false,
      });
    }
    if (!env.DB)   return jsonResponse({ terminal_enabled: true, terminal_configured: false });
    try {
      const row = await env.DB.prepare(
        `SELECT id, tunnel_url, shell, cwd, cols, rows
         FROM terminal_sessions
         WHERE user_id = ? AND status = 'active'
           AND tunnel_url IS NOT NULL AND tunnel_url != ''
         ORDER BY updated_at DESC LIMIT 1`
      ).bind(String(authUser.id)).first().catch(() => null);
      if (!row) return jsonResponse({ terminal_enabled: true, terminal_configured: false });
      return jsonResponse({
        terminal_enabled: true,
        terminal_configured: true,
        tunnel_url: row.tunnel_url,
        shell:      row.shell || 'bash',
        cwd:        row.cwd   || '~',
        cols:       row.cols  || 220,
        rows:       row.rows  || 50,
      });
    } catch (e) {
      return jsonResponse({ terminal_enabled: true, terminal_configured: false, error: e.message });
    }
  }

  // ── /api/agent/propose ────────────────────────────────────────────────────
  if (path === '/api/agent/propose' && method === 'POST') {
    const authUser = await getAuthUser(request, env);
    if (!authUser) return jsonResponse({ error: 'Unauthorized' }, 401);
    if (!env.DB)   return jsonResponse({ error: 'DB not configured' }, 503);
    const body        = await request.json().catch(() => ({}));
    const commandText = String(body.command_text || body.command || '').trim();
    if (!commandText) return jsonResponse({ error: 'command_text required' }, 400);
    let tenantId =
      authUser.tenant_id != null && String(authUser.tenant_id).trim() !== ''
        ? String(authUser.tenant_id).trim()
        : null;
    if (!tenantId) tenantId = await fetchAuthUserTenantId(env, authUser.id);
    if (!tenantId && authUser.email) tenantId = await fetchAuthUserTenantId(env, authUser.email);
    if (!tenantId) return jsonResponse({ error: 'Tenant not configured for this account' }, 403);
    const proposalId = 'prop_' + crypto.randomUUID().replace(/-/g,'').slice(0,16);
    const now        = Math.floor(Date.now() / 1000);
    const expProp    = now + 86400;
    const iamOrigin  = (env.IAM_ORIGIN || '').replace(/\/$/,'');
    await env.DB.prepare(
      `INSERT INTO agentsam_approval_queue
       (id, tenant_id, workspace_id, user_id, session_id, tool_name, action_summary,
        risk_level, input_json, expires_at, status, approval_type, created_at)
       VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?)`
    ).bind(
      proposalId,
      tenantId,
      null,
      String(authUser.email || authUser.id || 'iam_agent').slice(0, 200),
      body.session_id || null,
      String(body.command_name || 'proposed').slice(0, 200),
      String(body.rationale || 'Agent proposed command').slice(0, 8000),
      'medium',
      JSON.stringify({
        command_text: commandText,
        filled_template: commandText,
        command_source: 'agent_generated',
      }),
      expProp,
      'pending',
      'tool',
      now,
    ).run();
    notifySam(env, { subject: `Proposal pending: ${commandText.slice(0,80)}`, body: `ID: ${proposalId}\nApprove: ${iamOrigin}/dashboard/overview?proposal=${proposalId}`, category: 'proposal' }, ctx);
    return jsonResponse({ ok: true, proposal_id: proposalId });
  }

  // ── /api/agent/proposals/pending ─────────────────────────────────────────
  if (path === '/api/agent/proposals/pending' && method === 'GET') {
    const authUser = await getAuthUser(request, env);
    if (!authUser) return jsonResponse({ error: 'Unauthorized' }, 401);
    if (!env.DB)   return jsonResponse([]);
    const uid = String(authUser.id || '').trim();
    const wsQ = String(url.searchParams.get('workspace_id') || '').trim();
    const tid = String(authUser.tenant_id || '').trim();
    let sql = `SELECT q.id, q.tenant_id, q.session_id AS agent_session_id, q.user_id AS proposed_by,
              q.tool_name AS command_name,
              COALESCE(json_extract(q.input_json, '$.command_text'), q.action_summary) AS command_text,
              q.input_json AS filled_template, q.action_summary AS rationale, q.risk_level, q.status,
              q.created_at
       FROM agentsam_approval_queue q
       WHERE q.status = 'pending' AND q.user_id = ?`;
    const binds = [uid];
    if (wsQ) {
      sql += ` AND (q.workspace_id = ? OR (q.workspace_id IS NULL AND q.tenant_id = ?))`;
      binds.push(wsQ, tid);
    }
    sql += ` ORDER BY q.created_at DESC`;
    const { results } = await env.DB.prepare(sql).bind(...binds).all().catch(() => ({ results: [] }));
    return jsonResponse(results || []);
  }

  const propApproveMatch = path.match(/^\/api\/agent\/proposals\/([^/]+)\/approve$/);
  if (propApproveMatch && method === 'POST') {
    const authUser = await getAuthUser(request, env);
    if (!authUser) return jsonResponse({ error: 'Unauthorized' }, 401);
    if (!env.DB)   return jsonResponse({ error: 'DB not configured' }, 503);
    const propId   = propApproveMatch[1];
    const row = await env.DB
      .prepare(`SELECT id, tool_name AS tool, command_run_id FROM agentsam_approval_queue WHERE id = ?`)
      .bind(propId)
      .first();
    if (!row) return jsonResponse({ error: 'Not found' }, 404);
    const approver = String(authUser.email || authUser.id).slice(0, 200);
    const now = Math.floor(Date.now() / 1000);
    await env.DB
      .prepare(`UPDATE agentsam_approval_queue SET status='approved', approved_by=?, decided_at=? WHERE id=?`)
      .bind(approver, now, propId)
      .run();
    const crid = row.command_run_id != null ? String(row.command_run_id).trim() : '';
    if (crid) {
      await env.DB
        .prepare(`UPDATE agentsam_command_run SET approval_status = 'approved' WHERE id = ?`)
        .bind(crid)
        .run()
        .catch(() => null);
    }
    return jsonResponse({ ok: true, proposal_id: propId });
  }

  const propDenyMatch = path.match(/^\/api\/agent\/proposals\/([^/]+)\/deny$/);
  if (propDenyMatch && method === 'POST') {
    const authUser = await getAuthUser(request, env);
    if (!authUser) return jsonResponse({ error: 'Unauthorized' }, 401);
    if (!env.DB)   return jsonResponse({ error: 'DB not configured' }, 503);
    const propId   = propDenyMatch[1];
    await request.json().catch(() => ({}));
    const row      = await env.DB
      .prepare(`SELECT id, command_run_id, input_json, execution_step_id FROM agentsam_approval_queue WHERE id = ?`)
      .bind(propId)
      .first();
    if (!row) return jsonResponse({ error: 'Not found' }, 404);
    const denier   = String(authUser.email || authUser.id).slice(0,200);
    const now      = Math.floor(Date.now() / 1000);
    await env.DB.prepare(
      `UPDATE agentsam_approval_queue SET status='denied', approved_by=?, decided_at=? WHERE id=?`,
    ).bind(denier, now, propId).run();
    const crid = row.command_run_id != null ? String(row.command_run_id).trim() : '';
    if (crid) {
      await env.DB
        .prepare(`UPDATE agentsam_command_run SET approval_status = 'denied' WHERE id = ?`)
        .bind(crid)
        .run()
        .catch(() => null);
    }
    let inj = {};
    try {
      inj = JSON.parse(String(row.input_json || '{}'));
    } catch {
      inj = {};
    }
    const ptid = inj.plan_task_id != null ? String(inj.plan_task_id).trim() : '';
    const esid = inj.execution_step_id != null ? String(inj.execution_step_id).trim() : '';
    const denyNote = '[terminal] Denied — no command execution.';
    if (ptid) {
      await env.DB
        .prepare(
          `UPDATE agentsam_plan_tasks SET status='skipped', completed_at=unixepoch(), output_summary=? WHERE id=?`,
        )
        .bind(denyNote, ptid)
        .run()
        .catch(() => null);
    }
    const esTarget = esid || (row.execution_step_id != null ? String(row.execution_step_id).trim() : '');
    if (esTarget) {
      await env.DB
        .prepare(
          `UPDATE agentsam_execution_steps SET status='failed', output_json=?, error_json=? WHERE id=?`,
        )
        .bind(
          JSON.stringify({ denied: true, approval_id: propId }),
          JSON.stringify({ error: denyNote }),
          esTarget,
        )
        .run()
        .catch(() => null);
    }
    return jsonResponse({ ok: true, proposal_id: propId, status: 'denied' });
  }

  // ── /api/agent/approval/pending ───────────────────────────────────────────
  if (method === 'GET' && path === '/api/agent/approval/pending') {
    const authUser = await getAuthUser(request, env);
    if (!authUser) return jsonResponse({ error: 'Unauthorized' }, 401, { 'Cache-Control': 'no-store' });
    const workspaceId = String(url.searchParams.get('workspace_id') || '').trim();
    if (!workspaceId) {
      return jsonResponse({ pending: [] }, 200, { 'Cache-Control': 'no-store' });
    }
    const runId = String(url.searchParams.get('run_id') || '').trim();
    if (!env.DB) {
      return jsonResponse({ approval: null, pending_count: 0 }, 200, { 'Cache-Control': 'no-store' });
    }
    const uid = String(authUser.id || '').trim();
    const tid = String(authUser.tenant_id || '').trim();
    const scopeBinds = [uid, workspaceId, tid];
    const runBinds = runId ? [runId, runId, runId] : [];
    const runFilterTable = runId
      ? ` AND (workflow_run_id = ? OR session_id = ? OR command_run_id = ?)`
      : '';
    const runFilterAlias = runId
      ? ` AND (q.workflow_run_id = ? OR q.session_id = ? OR q.command_run_id = ?)`
      : '';

    const countRow = await env.DB.prepare(
      `SELECT COUNT(*) AS c FROM agentsam_approval_queue
       WHERE status='pending' AND user_id = ?
         AND (workspace_id = ? OR (workspace_id IS NULL AND tenant_id = ?))${runFilterTable}`,
    )
      .bind(...scopeBinds, ...runBinds)
      .first()
      .catch(() => ({ c: 0 }));
    const pendingCount = Number(countRow?.c || 0) || 0;

    const row = await env.DB.prepare(
      `SELECT q.id, q.tool_name, q.action_summary AS description, q.risk_level, q.input_json,
              0 AS is_mcp_server, NULL AS server_display_name
       FROM agentsam_approval_queue q
       WHERE q.status='pending' AND q.user_id = ?
         AND (q.workspace_id = ? OR (q.workspace_id IS NULL AND q.tenant_id = ?))${runFilterAlias}
       ORDER BY q.created_at ASC LIMIT 1`,
    )
      .bind(...scopeBinds, ...runBinds)
      .first()
      .catch(() => null);
    if (!row) {
      return jsonResponse({ approval: null, pending_count: pendingCount }, 200, { 'Cache-Control': 'no-store' });
    }
    const input = JSON.parse(row.input_json || '{}');
    return jsonResponse(
      {
        approval: {
          ...row,
          queue_count: pendingCount,
          preview_sql: input.sql ?? null,
          preview_command: input.command ?? null,
        },
        pending_count: pendingCount,
      },
      200,
      { 'Cache-Control': 'no-store' },
    );
  }

  // ── PATCH /api/agent/approval/:id ─────────────────────────────────────────
  const approvalMatch = path.match(/^\/api\/agent\/approval\/([^/]+)$/);
  if (method === 'PATCH' && approvalMatch) {
    const authUser = await getAuthUser(request, env);
    if (!authUser) return jsonResponse({ error: 'Unauthorized' }, 401);
    if (!env.DB) return jsonResponse({ error: 'DB not configured' }, 503);
    const { status } = await request.json().catch(() => ({}));
    if (!['approved', 'denied'].includes(status)) return jsonResponse({ error: 'invalid status' }, 400);
    const apId = approvalMatch[1];
    const prev = await env.DB
      .prepare(`SELECT command_run_id FROM agentsam_approval_queue WHERE id = ?`)
      .bind(apId)
      .first()
      .catch(() => null);
    await env.DB
      .prepare(`UPDATE agentsam_approval_queue SET status=?, decided_at=unixepoch(), approved_by=? WHERE id=?`)
      .bind(status, String(authUser.email || authUser.id).slice(0, 200), apId)
      .run();
    if (status === 'approved' && prev?.command_run_id) {
      const cr = String(prev.command_run_id).trim();
      if (cr) {
        await env.DB
          .prepare(`UPDATE agentsam_command_run SET approval_status = 'approved' WHERE id = ?`)
          .bind(cr)
          .run()
          .catch(() => null);
      }
    }
    return jsonResponse({ ok: true });
  }

  // ── POST /api/agent/plan-task/resume — one plan terminal task after Allow (SSE) ──
  if (path === '/api/agent/plan-task/resume' && method === 'POST') {
    const authUser = await getAuthUser(request, env);
    if (!authUser) return jsonResponse({ error: 'Unauthorized' }, 401);
    if (!env.DB) return jsonResponse({ error: 'DB not configured' }, 503);
    const body = await request.json().catch(() => ({}));
    const planId = String(body.plan_id ?? body.planId ?? '').trim();
    const taskId = String(body.task_id ?? body.taskId ?? '').trim();
    const commandRunIdIn = String(body.command_run_id ?? body.commandRunId ?? '').trim();
    const approvalId = String(body.approval_id ?? body.approvalId ?? '').trim();
    if (!planId || !taskId || !approvalId) {
      return jsonResponse({ error: 'plan_id, task_id, and approval_id required' }, 400);
    }

    const wsRes = await resolveEffectiveWorkspaceId(env, request, authUser, {}).catch(() => null);
    const workspaceId =
      (authUser.active_workspace_id != null && String(authUser.active_workspace_id).trim() !== ''
        ? String(authUser.active_workspace_id).trim()
        : null) ||
      (wsRes && !wsRes.error && wsRes.workspaceId ? String(wsRes.workspaceId).trim() : null);
    if (!workspaceId) return jsonResponse({ error: 'no_workspace', redirect: '/onboarding' }, 403);

    let tenantId =
      authUser.tenant_id != null && String(authUser.tenant_id).trim() !== ''
        ? String(authUser.tenant_id).trim()
        : null;
    if (!tenantId) tenantId = await fetchAuthUserTenantId(env, authUser.id);

    const uid = String(authUser.id || '').trim();
    const canon = await resolveCanonicalUserId(uid, env).catch(() => uid);

    const qRow = await env.DB
      .prepare(
        `SELECT q.id, q.status, q.command_run_id, q.user_id, q.expires_at, q.execution_step_id
         FROM agentsam_approval_queue q
         WHERE q.id = ? AND lower(q.status) = 'approved'
           AND (q.expires_at IS NULL OR q.expires_at > unixepoch())`,
      )
      .bind(approvalId)
      .first()
      .catch(() => null);

    if (!qRow?.id) {
      return jsonResponse({ error: 'approval_not_verified', message: 'Approve this task first (Allow).' }, 403);
    }

    const qCrid = qRow.command_run_id != null ? String(qRow.command_run_id).trim() : '';
    if (commandRunIdIn && qCrid && qCrid !== commandRunIdIn) {
      return jsonResponse({ error: 'command_run_mismatch' }, 400);
    }
    const effectiveCrid = commandRunIdIn || qCrid;
    if (!effectiveCrid) {
      return jsonResponse({ error: 'command_run_id missing' }, 400);
    }

    const tRow = await env.DB
      .prepare(
        `SELECT id, plan_id, workspace_id, command_run_id, execution_step_id FROM agentsam_plan_tasks WHERE id = ? AND plan_id = ? LIMIT 1`,
      )
      .bind(taskId, planId)
      .first()
      .catch(() => null);

    if (!tRow?.id) return jsonResponse({ error: 'task_not_found' }, 404);
    const tws = String(tRow.workspace_id || '').trim();
    if (tws && tws !== workspaceId) {
      return jsonResponse({ error: 'workspace_mismatch' }, 403);
    }
    const tcr = tRow.command_run_id != null ? String(tRow.command_run_id).trim() : '';
    if (tcr && tcr !== effectiveCrid) {
      return jsonResponse({ error: 'task_command_run_mismatch' }, 400);
    }

    const qEs = qRow.execution_step_id != null ? String(qRow.execution_step_id).trim() : '';
    const tEs = tRow.execution_step_id != null ? String(tRow.execution_step_id).trim() : '';
    if (qEs && tEs && qEs !== tEs) {
      return jsonResponse({ error: 'execution_step_mismatch' }, 400);
    }

    const quid = String(qRow.user_id || '').trim();
    if (quid && quid !== canon && quid !== uid) {
      return jsonResponse({ error: 'approval_user_mismatch' }, 403);
    }

    const planRow = await env.DB
      .prepare(`SELECT workflow_run_id FROM agentsam_plans WHERE id = ? LIMIT 1`)
      .bind(planId)
      .first()
      .catch(() => null);
    const wfResume =
      planRow?.workflow_run_id != null && String(planRow.workflow_run_id).trim() !== ''
        ? String(planRow.workflow_run_id).trim()
        : null;

    await env.DB
    const { readable, writable } = new TransformStream();
    const writer = writable.getWriter();
    const emitResume = (event, data) => {
      try {
        writer.write(encoder.encode(`data: ${JSON.stringify({ type: event, ...data })}\n\n`));
      } catch (_) {}
    };

    (async () => {
      try {
        const { executePlan } = await import('../core/agentsam-task-executor.js');
        await executePlan(env, {
          planId,
          userId: uid,
          workspaceId,
          tenantId,
          emit: emitResume,
          ctx,
          onlyTaskId: taskId,
          sessionId: body.sessionId ?? body.session_id ?? null,
          skipPlanAggregate: true,
          workflowRunId: wfResume,
        });
        emitResume('done', {});
      } catch (e) {
        emitResume('text', { text: `**Resume error:** ${e?.message ?? String(e)}` });
        emitResume('done', {});
      } finally {
        writer.close().catch(() => {});
      }
    })();

    return new Response(readable, {
      headers: {
        'Content-Type': 'text/event-stream',
        'Cache-Control': 'no-cache',
        Connection: 'keep-alive',
        'Access-Control-Allow-Origin': '*',
      },
    });
  }

  // ── POST /api/agent/workflow/start — DAG graph executor (agentsam_workflow_*)
  if (path === '/api/agent/workflow/start' && method === 'POST') {
    const authUser = await getAuthUser(request, env);
    if (!authUser) return jsonResponse({ error: 'Unauthorized' }, 401);
    if (!env.DB) return jsonResponse({ error: 'DB not configured' }, 503);
    const body = await request.json().catch(() => ({}));
    const { workflow_key: workflowKeyBody, input, trigger_type: triggerTypeBody } = body;
    if (!workflowKeyBody) return jsonResponse({ error: 'workflow_key required' }, 400);
    const { executeWorkflowGraph } = await import('../core/workflow-executor.js');
    let tenantId =
      authUser.tenant_id != null && String(authUser.tenant_id).trim() !== ''
        ? String(authUser.tenant_id).trim()
        : null;
    if (!tenantId) tenantId = await fetchAuthUserTenantId(env, authUser.id);
    if (!tenantId) return jsonResponse({ error: 'Tenant could not be resolved' }, 403);
    const wsRes = await resolveEffectiveWorkspaceId(env, request, authUser, {}).catch(() => null);
    const workspaceId =
      (authUser.active_workspace_id != null && String(authUser.active_workspace_id).trim() !== ''
        ? String(authUser.active_workspace_id).trim()
        : null) ||
      (wsRes && !wsRes.error && wsRes.workspaceId ? String(wsRes.workspaceId).trim() : null);
    if (!workspaceId) return jsonResponse({ error: 'no_workspace', redirect: '/onboarding' }, 403);
    const result = await executeWorkflowGraph(env, {
      workflowKey: String(workflowKeyBody).trim(),
      input: input || {},
      tenantId,
      workspaceId,
      userId: authUser.id,
      userEmail: authUser.email,
      triggerType: triggerTypeBody,
    });
    return jsonResponse(result);
  }

  // ── POST /api/agent/workflow/approve — resume workflow after approval_gate
  if (path === '/api/agent/workflow/approve' && method === 'POST') {
    const authUser = await getAuthUser(request, env);
    if (!authUser) return jsonResponse({ error: 'Unauthorized' }, 401);
    const body = await request.json().catch(() => ({}));
    const { approval_id: approvalId, decision } = body;
    if (!approvalId) return jsonResponse({ error: 'approval_id required' }, 400);
    if (!['approved', 'rejected'].includes(decision)) {
      return jsonResponse({ error: 'decision must be approved or rejected' }, 400);
    }
    if (!env.DB) return jsonResponse({ error: 'DB unavailable' }, 503);

    const statusDb = decision === 'approved' ? 'approved' : 'denied';

    const updated = await env.DB.prepare(
      `UPDATE agentsam_approval_queue
       SET status      = ?,
           approved_by = ?,
           decided_at  = unixepoch()
       WHERE id = ? AND status = 'pending'`,
    )
      .bind(statusDb, authUser.id, approvalId)
      .run()
      .catch(() => null);

    const changes = updated?.meta?.changes ?? updated?.changes ?? 0;
    if (!changes) {
      return jsonResponse({ error: 'approval not found or already decided' }, 404);
    }

    const apRow = await env.DB.prepare(`SELECT workflow_run_id FROM agentsam_approval_queue WHERE id = ?`)
      .bind(approvalId)
      .first()
      .catch(() => null);

    if (apRow?.workflow_run_id && decision === 'approved') {
      await env.DB.prepare(
        `UPDATE agentsam_workflow_runs
         SET status = 'running', updated_at = datetime('now')
         WHERE id = ? AND status = 'awaiting_approval'`,
      )
        .bind(apRow.workflow_run_id)
        .run()
        .catch(() => null);
    }

    if (apRow?.workflow_run_id && decision === 'rejected') {
      await env.DB.prepare(
        `UPDATE agentsam_workflow_runs
         SET status = 'failed', kill_reason = 'approval_rejected', updated_at = datetime('now')
         WHERE id = ?`,
      )
        .bind(apRow.workflow_run_id)
        .run()
        .catch(() => null);
    }

    return jsonResponse({
      ok: true,
      decision,
      approval_id: approvalId,
      run_id: apRow?.workflow_run_id ?? null,
      message:
        decision === 'approved'
          ? 'Approved. Workflow will resume on next heartbeat.'
          : 'Rejected. Workflow run marked failed.',
    });
  }

  // ── /api/agent/workflows/trigger ─────────────────────────────────────────
  if (path === '/api/agent/workflows/trigger' && method === 'POST') {
    const authUser = await getAuthUser(request, env);
    if (!authUser) return jsonResponse({ error: 'Unauthorized' }, 401);
    if (!env.DB)   return jsonResponse({ error: 'DB not configured' }, 503);
    const body         = await request.json().catch(() => ({}));
    const workflowName = String(body.workflow_name || '').trim();
    if (!workflowName) return jsonResponse({ error: 'workflow_name required' }, 400);
    let tenantId =
      authUser.tenant_id != null && String(authUser.tenant_id).trim() !== ''
        ? String(authUser.tenant_id).trim()
        : null;
    if (!tenantId) tenantId = await fetchAuthUserTenantId(env, authUser.id);
    if (!tenantId && authUser.email) tenantId = await fetchAuthUserTenantId(env, authUser.email);
    if (!tenantId) return jsonResponse({ error: 'Tenant could not be resolved' }, 403);
    const runId        = 'wfr_' + crypto.randomUUID().replace(/-/g,'').slice(0,16);
    await env.DB.prepare(`INSERT INTO workflow_runs (id, tenant_id, workflow_id, workflow_name, trigger_source, triggered_by, status, input_data, created_at, updated_at) VALUES (?,?,?,?,'api','iam_agent','pending',?,datetime('now'),datetime('now'))`).bind(runId, tenantId, body.workflow_id||null, workflowName, body.input_data ? JSON.stringify(body.input_data) : null).run();
    return jsonResponse({ ok: true, run_id: runId, status: 'pending' });
  }

  // ── /api/agent/rag/query ──────────────────────────────────────────────────
  if (path === '/api/agent/rag/query' && method === 'POST') {
    const body  = await request.json().catch(() => ({}));
    const query = (body.query || body.q || '').trim();
    if (!query) return jsonResponse({ error: 'query required', matches: [], results: [], count: 0 }, 400);
    const out = await unifiedRagSearch(env, query, {
      topK: body.top_k || 8,
      tenantId: identity?.tenantId ?? null,
      workspaceId: identity?.workspaceId ?? null,
      sessionId: identity?.sessionId ?? null,
    });
    return jsonResponse({ matches: out.matches||[], results: out.results||[], count: out.count||0 });
  }

  // ── /api/agent/workers-ai/image ───────────────────────────────────────────
  if (path === '/api/agent/workers-ai/image' && method === 'POST') {
    if (!env.AI) return jsonResponse({ error: 'Workers AI not configured' }, 503);
    if (!env.DB) return jsonResponse({ error: 'DB not configured' }, 503);
    if (!identity?.tenantId) return jsonResponse({ error: 'unauthenticated' }, 401);
    const body   = await request.json().catch(() => ({}));
    const prompt = String(body.prompt || '').trim();
    if (!prompt) return jsonResponse({ error: 'prompt required' }, 400);
    let modelRow = await env.DB.prepare(
      `SELECT model_key FROM agentsam_ai
       WHERE mode = 'model' AND status = 'active'
         AND (is_global = 1 OR allowed_tenants_json LIKE ('%"' || ? || '"%'))
         AND LOWER(COALESCE(api_platform, '')) = 'workers_ai'
         AND (
           LOWER(COALESCE(name, '')) LIKE '%image%'
           OR LOWER(model_key) LIKE '%flux%'
         )
       ORDER BY COALESCE(sort_order, 999), COALESCE(input_rate_per_mtok, 999999) ASC
       LIMIT 1`,
    )
      .bind(identity.tenantId)
      .first()
      .catch(() => null);
    let model = modelRow?.model_key;
    if (!model) {
      modelRow = await env.DB.prepare(
        `SELECT model_key FROM agentsam_ai
         WHERE mode = 'model' AND status = 'active'
           AND (is_global = 1 OR allowed_tenants_json LIKE ('%"' || ? || '"%'))
           AND LOWER(COALESCE(api_platform, '')) = 'workers_ai'
         ORDER BY COALESCE(sort_order, 999), COALESCE(input_rate_per_mtok, 999999) ASC
         LIMIT 1`,
      )
        .bind(identity.tenantId)
        .first()
        .catch(() => null);
      model = modelRow?.model_key;
    }
    if (!model) return jsonResponse({ error: 'No active Workers AI image model in agentsam_ai' }, 503);
    try {
      const result = await env.AI.run(model, { prompt });
      const bytes  = result instanceof ArrayBuffer ? new Uint8Array(result) : result;
      return new Response(bytes, { headers: { 'Content-Type': 'image/png' } });
    } catch (e) { return jsonResponse({ error: e?.message }, 500); }
  }

  // ── /api/agent/do-history ─────────────────────────────────────────────────
  if (path === '/api/agent/do-history' && method === 'GET') {
    if (!identity?.userId) return jsonResponse({ error: 'unauthenticated' }, 401);
    const convId = url.searchParams.get('conversation_id');
    if (!convId) return jsonResponse({ error: 'conversation_id required' }, 400);
    if (!env.AGENT_SESSION) return jsonResponse({ error: 'AGENT_SESSION not configured' }, 503);
    const doId = env.AGENT_SESSION.idFromName(String(convId));
    const stub = env.AGENT_SESSION.get(doId);
    const lim  = url.searchParams.get('limit') || '50';
    const resp = await stub.fetch(new Request(`https://do/history?limit=${encodeURIComponent(lim)}`));
    return new Response(resp.body, { status: resp.status, headers: { 'Content-Type': 'application/json' } });
  }

  // ── /api/agent/telemetry ──────────────────────────────────────────────────
  if (path === '/api/agent/telemetry') {
    if (!env.DB) return jsonResponse([]);
    const { results } = await env.DB.prepare(`SELECT provider, SUM(tokens_in) as total_input, SUM(tokens_out) as total_output, COUNT(*) as total_calls FROM agentsam_usage_events WHERE created_at > unixepoch('now','-7 days') GROUP BY provider`).all().catch(() => ({ results: [] }));
    return jsonResponse(results || []);
  }

  // ── /api/agent/cicd ───────────────────────────────────────────────────────
  if (path === '/api/agent/cicd') {
    if (!env.DB) return jsonResponse([]);
    const { results } = await env.DB.prepare(`SELECT r.id, r.worker_name, r.environment, r.status, r.git_branch, r.git_commit_sha, r.queued_at, r.completed_at, COUNT(e.id) AS activity_count FROM cicd_runs r LEFT JOIN cicd_events e ON e.webhook_event_id = r.id GROUP BY r.id ORDER BY r.queued_at DESC LIMIT 50`).all().catch(() => ({ results: [] }));
    return jsonResponse(results || []);
  }

  // ── /api/agent/mcp ────────────────────────────────────────────────────────
  if (path === '/api/agent/mcp') {
    if (!env.DB) return jsonResponse([]);
    const { results } = await env.DB.prepare(`SELECT id, service_name, service_type, endpoint_url, is_active, health_status FROM mcp_services WHERE is_active=1 ORDER BY service_name`).all().catch(() => ({ results: [] }));
    return jsonResponse(results || []);
  }

  // ── /api/agent/bootstrap ──────────────────────────────────────────────────
  if (path === '/api/agent/bootstrap' && method === 'GET') {
    if (!identity) return jsonResponse({ error: 'unauthenticated' }, 401);
    return handleAgentBootstrapRequest(request, env, ctx, identity);
  }

  // ── /api/agent/chat ───────────────────────────────────────────────────────
  if (path === '/api/agent/chat' && method === 'POST') {
    const ingestBypass = isIngestSecretAuthorized(request, env);
    return agentChatSseHandler(env, request, ctx, { ingestBypass, identity });
  }

  return jsonResponse({ error: 'Agent route not found', path }, 404);
}

export async function handleAgentRequest(request, env, ctx, _authUser = null) {
  const url = new URL(request.url);
  return handleAgentApi(request, url, env, ctx);
}

// ─── Bootstrap ────────────────────────────────────────────────────────────────

async function handleAgentBootstrapRequest(request, env, ctx, identity) {
  try {
    const userId   = identity?.userId || 'system';
    const cacheKey = `bootstrap_${userId}`;
    if (env.DB) {
      const cached = await env.DB.prepare(`SELECT compiled_context FROM ai_compiled_context_cache WHERE context_hash = ? AND (expires_at IS NULL OR expires_at > unixepoch())`).bind(cacheKey).first().catch(() => null);
      if (cached?.compiled_context) {
        return new Response(cached.compiled_context, { headers: { 'Content-Type': 'application/json', 'X-Cache': 'HIT' } });
      }
    }
    const today     = new Date().toISOString().slice(0, 10);
    const yesterday = new Date(Date.now() - 86400000).toISOString().slice(0, 10);
    let dailyLog = '', yesterdayLog = '', schemaMemory = '', todayTodo = '';
    if (env.R2) {
      const fetchR2 = async k => { const o = await env.R2.get(k); return o ? await o.text() : ''; };
      [dailyLog, yesterdayLog, schemaMemory, todayTodo] = await Promise.all([
        fetchR2(`memory/daily/${today}.md`),
        fetchR2(`memory/daily/${yesterday}.md`),
        fetchR2('memory/schema-and-records.md'),
        fetchR2('memory/today-todo.md'),
      ]);
    }
    if (!todayTodo && env.DB) {
      const row = await env.DB.prepare(`SELECT value FROM agentsam_memory WHERE key = 'today_todo' AND tenant_id = ?`).bind(identity?.tenantId || null).first().catch(() => null);
      if (row?.value) todayTodo = String(row.value);
    }
    const context = { daily_log: dailyLog || null, yesterday_log: yesterdayLog || null, schema_and_records_memory: schemaMemory || null, today_todo: todayTodo || null, date: today };
    if (env.DB && ctx?.waitUntil) {
      ctx.waitUntil(
        env.DB.prepare(`INSERT INTO ai_compiled_context_cache (id, context_hash, context_type, compiled_context, source_context_ids_json, token_count, tenant_id, created_at, last_accessed_at, expires_at) VALUES (?,?,'bootstrap',?,'[]',0,?,unixepoch(),unixepoch(),unixepoch()+1800) ON CONFLICT(context_hash) DO UPDATE SET compiled_context=excluded.compiled_context, expires_at=excluded.expires_at, last_accessed_at=unixepoch()`).bind(cacheKey, cacheKey, JSON.stringify(context), identity?.tenantId || null).run().catch(() => {})
      );
    }
    return jsonResponse(context);
  } catch (e) {
    return jsonResponse({ error: String(e.message || e) }, 500);
  }
}

/**
 * RAG API — OpenAI embeddings + Supabase (Hyperdrive/pgvector) + R2 (S3-compatible).
 * No AI Search, Vectorize, or Workers AI embedding models on this path.
 */
import { AwsClient } from 'aws4fetch';
import { jsonResponse } from '../core/responses.js';
import { getAuthUser, fetchAuthUserTenantId } from '../core/auth.js';
import { runHyperdriveQuery } from '../core/hyperdrive-query.js';

export const RAG_CHUNK_MAX_CHARS = 600;
export const RAG_CHUNK_OVERLAP = 80;
export const RAG_EMBED_BATCH_SIZE = 32;
export const RAG_COMPACT_MAX_MSG_CHARS = 800;
export const RAG_COMPACT_HOURS = 48;

// ── small utilities (kept for callers / chunking) ─────────────────────────────

export function sanitizeUnifiedRagLike(q) {
  return String(q || '').slice(0, 120).replace(/[%_\[\]^]/g, ' ').trim();
}

export function unifiedRagContentHash(s) {
  const t = String(s || '').trim().replace(/\s+/g, ' ').slice(0, 600);
  let h = 2166136261;
  for (let i = 0; i < t.length; i++) {
    h ^= t.charCodeAt(i);
    h = Math.imul(h, 16777619);
  }
  return String(h);
}

export function unifiedRagRecency01(ts) {
  const now = Math.floor(Date.now() / 1000);
  let sec = 0;
  if (!ts) return 0.5;
  if (typeof ts === 'number') {
    sec = ts > 1e12 ? Math.floor(ts / 1000) : Math.floor(ts);
  } else {
    const parsed = Date.parse(String(ts));
    if (Number.isNaN(parsed)) return 0.5;
    sec = Math.floor(parsed / 1000);
  }
  const ageDays = Math.max(0, (now - sec) / 86400);
  return Math.max(0, Math.min(1, 1 - Math.min(ageDays, 365) / 365));
}

export function unifiedRagCosine(a, b) {
  let dot = 0;
  let na = 0;
  let nb = 0;
  const len = Math.min(a.length, b.length);
  for (let i = 0; i < len; i++) {
    dot += a[i] * b[i];
    na += a[i] * a[i];
    nb += b[i] * b[i];
  }
  return dot / (Math.sqrt(na) * Math.sqrt(nb) + 1e-8);
}

function timingSafeEqualUtf8(a, b) {
  if (a.length !== b.length) return false;
  let x = 0;
  for (let i = 0; i < a.length; i++) x |= a.charCodeAt(i) ^ b.charCodeAt(i);
  return x === 0;
}

async function hmacSha256HexFromUtf8Key(secretUtf8, messageUtf8) {
  const key = await crypto.subtle.importKey(
    'raw',
    new TextEncoder().encode(secretUtf8),
    { name: 'HMAC', hash: 'SHA-256' },
    false,
    ['sign']
  );
  const sig = await crypto.subtle.sign('HMAC', key, new TextEncoder().encode(messageUtf8));
  return [...new Uint8Array(sig)].map((c) => c.toString(16).padStart(2, '0')).join('');
}

async function verifySupabaseWebhookSignature(secret, rawBody, sigHeader) {
  if (!secret || !sigHeader) return false;
  const trimmed = String(sigHeader).trim();
  const got = trimmed.replace(/^sha256=/i, '').trim().toLowerCase();
  if (!/^[0-9a-f]{64}$/.test(got)) return false;
  const expectedHex = (await hmacSha256HexFromUtf8Key(secret, rawBody)).toLowerCase();
  return timingSafeEqualUtf8(expectedHex, got);
}

function ragAgentId(env) {
  return String(env.RAG_AGENT_ID || '').trim();
}

function ragDocumentsProjectId(env) {
  return String(env.RAG_DOCUMENTS_PROJECT_ID || '').trim();
}

export function ragEmbeddingModel(env) {
  return String(env.RAG_OPENAI_EMBEDDING_MODEL || '').trim();
}

export function ragEmbeddingDims(env) {
  const n = Number(env.RAG_EMBEDDING_DIMENSIONS || 1024);
  return Number.isFinite(n) && n > 0 ? n : NaN;
}

function r2AutoragBucketName(env) {
  return String(env.R2_AUTORAG_BUCKET_NAME || '').trim();
}

function openaiEmbeddingsBaseUrl(env) {
  const b = String(env.OPENAI_API_BASE_URL || '').trim().replace(/\/$/, '');
  if (!b) throw new Error('OPENAI_API_BASE_URL not configured');
  return b;
}

function verifyInternalSecret(request, env) {
  const secret = env.INTERNAL_API_SECRET;
  if (!secret || typeof secret !== 'string') return false;
  const auth = request.headers.get('Authorization') || '';
  const bearer = auth.startsWith('Bearer ') ? auth.slice(7).trim() : '';
  const header = (request.headers.get('X-Internal-Secret') || '').trim();
  const token = bearer || header;
  return token === secret;
}

function resolveAutoragFolder(env, metadata) {
  const prefixes = String(env.RAG_AUTORAG_FOLDER_PREFIXES || '')
    .split(',')
    .map((s) => s.trim())
    .filter(Boolean);
  const fallback = prefixes[0] || 'knowledge/';
  const folder = metadata && metadata.folder != null ? String(metadata.folder) : '';
  const normalized = folder.endsWith('/') ? folder : folder ? `${folder}/` : '';
  if (normalized && prefixes.includes(normalized)) return normalized;
  return fallback;
}

function safeObjectSuffix(source) {
  const s = String(source || 'doc')
    .replace(/[^a-zA-Z0-9._-]+/g, '_')
    .slice(0, 200);
  return s || 'doc';
}

function r2AwsClient(env) {
  const accessKeyId = env.R2_ACCESS_KEY_ID;
  const secretAccessKey = env.R2_SECRET_ACCESS_KEY;
  if (!accessKeyId || !secretAccessKey) return null;
  return new AwsClient({
    accessKeyId,
    secretAccessKey,
    service: 's3',
    region: 'auto',
  });
}

function parseListKeys(xml) {
  const keys = [];
  const re = /<Key>([^<]*)<\/Key>/g;
  let m;
  while ((m = re.exec(xml))) keys.push(m[1]);
  return keys;
}

function parseListTruncated(xml) {
  return /<IsTruncated>\s*true\s*<\/IsTruncated>/i.test(xml);
}

function parseNextContinuationToken(xml) {
  const m = xml.match(/<NextContinuationToken>([^<]*)<\/NextContinuationToken>/);
  return m ? m[1] : '';
}

async function r2ListAllObjectKeys(env) {
  const accountId = String(env.CLOUDFLARE_ACCOUNT_ID || '').trim();
  const bucket = r2AutoragBucketName(env);
  const client = r2AwsClient(env);
  if (!accountId || !bucket || !client) throw new Error('R2 list: missing account, bucket name, or credentials');
  const keys = [];
  let token = '';
  do {
    const q = new URLSearchParams({ 'list-type': '2' });
    if (token) q.set('continuation-token', token);
    const url = `https://${accountId}.r2.cloudflarestorage.com/${bucket}?${q}`;
    const res = await client.fetch(url);
    if (!res.ok) throw new Error(`R2 ListObjects failed: ${res.status}`);
    const xml = await res.text();
    keys.push(...parseListKeys(xml));
    const truncated = parseListTruncated(xml);
    token = truncated ? parseNextContinuationToken(xml) : '';
  } while (token);
  return keys;
}

function encodeS3ObjectKey(key) {
  return String(key)
    .split('/')
    .filter((seg) => seg.length > 0)
    .map((seg) => encodeURIComponent(seg))
    .join('/');
}

async function r2GetObjectText(env, key) {
  const accountId = String(env.CLOUDFLARE_ACCOUNT_ID || '').trim();
  const bucket = r2AutoragBucketName(env);
  const client = r2AwsClient(env);
  if (!accountId || !bucket || !client) throw new Error('R2 get: missing account, bucket name, or credentials');
  const url = `https://${accountId}.r2.cloudflarestorage.com/${bucket}/${encodeS3ObjectKey(key)}`;
  const res = await client.fetch(url);
  if (!res.ok) throw new Error(`R2 GetObject failed: ${res.status}`);
  return await res.text();
}

async function r2PutObjectText(env, key, bodyText) {
  const accountId = String(env.CLOUDFLARE_ACCOUNT_ID || '').trim();
  const bucket = r2AutoragBucketName(env);
  const client = r2AwsClient(env);
  if (!accountId || !bucket || !client) throw new Error('R2 put: missing account, bucket name, or credentials');
  const url = `https://${accountId}.r2.cloudflarestorage.com/${bucket}/${encodeS3ObjectKey(key)}`;
  const res = await client.fetch(url, {
    method: 'PUT',
    body: bodyText,
    headers: { 'Content-Type': 'text/plain; charset=utf-8' },
  });
  if (!res.ok) throw new Error(`R2 PutObject failed: ${res.status}`);
}

async function openaiCreateEmbedding(env, inputText) {
  const apiKey = env.OPENAI_API_KEY;
  const model = ragEmbeddingModel(env);
  const dims = ragEmbeddingDims(env);
  if (!apiKey) throw new Error('OPENAI_API_KEY not configured');
  if (!model) throw new Error('RAG_OPENAI_EMBEDDING_MODEL not configured');
  if (!Number.isFinite(dims)) throw new Error('RAG_EMBEDDING_DIMENSIONS not configured');
  const base = openaiEmbeddingsBaseUrl(env);
  const res = await fetch(`${base}/embeddings`, {
    method: 'POST',
    headers: {
      Authorization: `Bearer ${apiKey}`,
      'Content-Type': 'application/json',
    },
    body: JSON.stringify({
      model,
      input: inputText,
      dimensions: dims,
    }),
  });
  const raw = await res.text();
  let data;
  try {
    data = JSON.parse(raw);
  } catch {
    throw new Error(`OpenAI embeddings: non-JSON response (${res.status})`);
  }
  if (!res.ok) {
    throw new Error(data?.error?.message || `OpenAI embeddings HTTP ${res.status}`);
  }
  const vec = data?.data?.[0]?.embedding;
  if (!Array.isArray(vec)) throw new Error('OpenAI embeddings: missing vector');
  return vec;
}

function vectorLiteral(vec) {
  return `[${vec.join(',')}]`;
}

async function withPg(env, fn) {
  const cs = env.HYPERDRIVE?.connectionString;
  if (!cs) throw new Error('HYPERDRIVE not configured');
  const { Client } = await import('pg');
  const client = new Client({ connectionString: cs });
  await client.connect();
  try {
    return await fn(client);
  } finally {
    await client.end().catch(() => {});
  }
}

/**
 * Hybrid keyword + vector search against Supabase `agent_memory` via Hyperdrive (pgvector RPC).
 * Uses OpenAI embeddings (same model/dims as RAG). Returns null on missing bindings or errors.
 *
 * @param {any} env
 * @param {string} query
 * @param {string|null|undefined} workspaceId
 * @param {{ matchLimit?: number, keywordWeight?: number, semanticWeight?: number }} [options]
 * @returns {Promise<Array<{ id: unknown, content: unknown, hybrid_score?: unknown, embedding_distance?: unknown, trigram_similarity?: unknown }>|null>}
 */
export async function searchAgentMemoryHybrid(env, query, workspaceId, options = {}) {
  if (!env.HYPERDRIVE?.connectionString || !env.OPENAI_API_KEY) return null;

  const {
    matchLimit = 10,
    keywordWeight = 1.5,
    semanticWeight = 0.5,
  } = options;

  let embedding;
  try {
    embedding = await openaiCreateEmbedding(env, String(query || '').trim());
  } catch (e) {
    console.warn('[rag] searchAgentMemoryHybrid embed:', e?.message ?? e);
    return null;
  }
  if (!embedding?.length) return null;

  const vecLit = vectorLiteral(embedding);
  const q = String(query || '').trim();

  const sql = `SELECT id, content, hybrid_score, embedding_distance, trigram_similarity
     FROM public.search_agent_memory($1::vector, $2, $3, $4, $5, $6)`;
  const params = [vecLit, q, workspaceId, matchLimit, keywordWeight, semanticWeight];

  try {
    const r = await runHyperdriveQuery(env, sql, params);
    if (!r.ok) return null;
    return r.rows ?? [];
  } catch (e) {
    console.error('[rag] searchAgentMemoryHybrid failed:', e?.message);
    return null;
  }
}

async function upsertDocument(env, { source, title, content, embedding, projectId, metadata }) {
  const vecLit = vectorLiteral(embedding);
  const metaJson = JSON.stringify(metadata ?? {});

  return withPg(env, async (client) => {
    const tryWithMeta = async () => {
      const sel = await client.query(
        `SELECT id FROM public.documents WHERE source = $1 AND project_id = $2 LIMIT 1`,
        [source, projectId]
      );
      if (sel.rows?.length) {
        await client.query(
          `UPDATE public.documents SET title = $3, content = $4, embedding = $5::vector, metadata = $6::jsonb, updated_at = now()
           WHERE source = $1 AND project_id = $2`,
          [source, projectId, title, content, vecLit, metaJson]
        );
      } else {
        await client.query(
          `INSERT INTO public.documents (source, title, content, embedding, project_id, metadata, created_at, updated_at)
           VALUES ($1, $2, $3, $4::vector, $5, $6::jsonb, now(), now())`,
          [source, title, content, vecLit, projectId, metaJson]
        );
      }
    };
    const tryBasic = async () => {
      const sel = await client.query(
        `SELECT id FROM public.documents WHERE source = $1 AND project_id = $2 LIMIT 1`,
        [source, projectId]
      );
      if (sel.rows?.length) {
        await client.query(
          `UPDATE public.documents SET title = $3, content = $4, embedding = $5::vector WHERE source = $1 AND project_id = $2`,
          [source, projectId, title, content, vecLit]
        );
      } else {
        await client.query(
          `INSERT INTO public.documents (source, title, content, embedding, project_id, created_at)
           VALUES ($1, $2, $3, $4::vector, $5, now())`,
          [source, title, content, vecLit, projectId]
        );
      }
    };
    try {
      await tryWithMeta();
    } catch (e) {
      const msg = String(e?.message || '');
      if (msg.includes('metadata') || msg.includes('updated_at')) {
        await tryBasic();
      } else {
        throw e;
      }
    }
  });
}

async function documentSourceExists(env, source, projectId) {
  return withPg(env, async (client) => {
    const res = await client.query(
      `SELECT 1 FROM public.documents WHERE source = $1 AND project_id = $2 LIMIT 1`,
      [source, projectId]
    );
    return (res.rows || []).length > 0;
  });
}

/**
 * Insert one observability row into `public.semantic_search_log` (Hyperdrive / pg).
 * Skips when tenant_id is missing (required NOT NULL + RLS tenant scope).
 *
 * @param {any} env
 * @param {{
 *   searchFn: string,
 *   tenantId?: string | null,
 *   sessionId?: string | null,
 *   queryPreview?: string,
 *   matchThreshold: number,
 *   matchCountRequested: number,
 *   matchCountReturned: number,
 *   topSimilarity?: number | null,
 *   avgSimilarity?: number | null,
 *   sourcesHit?: string[],
 *   latencyMs?: number,
 *   metadata?: Record<string, unknown>,
 * }} args
 */
export async function logSemanticSearch(env, args) {
  const tenantRaw = args.tenantId != null ? String(args.tenantId).trim() : '';
  if (!tenantRaw) return;

  const {
    searchFn,
    sessionId,
    queryPreview,
    matchThreshold,
    matchCountRequested,
    matchCountReturned,
    topSimilarity,
    avgSimilarity,
    sourcesHit,
    latencyMs,
    metadata,
  } = args;

  const metaObj = metadata && typeof metadata === 'object' && !Array.isArray(metadata) ? metadata : {};
  const sessionTrim =
    sessionId != null && String(sessionId).trim() !== '' ? String(sessionId).trim().slice(0, 500) : null;

  const params = [
    String(searchFn || 'unknown').slice(0, 200),
    tenantRaw,
    sessionTrim,
    String(queryPreview ?? '').slice(0, 300),
    matchThreshold,
    matchCountRequested,
    matchCountReturned,
    topSimilarity ?? null,
    avgSimilarity ?? null,
    JSON.stringify(Array.isArray(sourcesHit) ? sourcesHit : []),
    Math.max(0, Math.floor(latencyMs ?? 0)),
    JSON.stringify(metaObj),
  ];

  const sql = `INSERT INTO public.semantic_search_log (
    search_fn, tenant_id, session_id, query_preview,
    match_threshold, match_count_requested, match_count_returned,
    top_similarity, avg_similarity, sources_hit, latency_ms, metadata
  ) VALUES (
    $1::text, $2::text, $3::text, $4::text,
    $5::double precision, $6::integer, $7::integer,
    $8::double precision, $9::double precision,
    $10::jsonb, $11::integer, $12::jsonb
  )`;

  try {
    const r = await runHyperdriveQuery(env, sql, params);
    if (!r.ok) await withPg(env, (client) => client.query(sql, params));
  } catch (e) {
    console.warn('[rag] semantic_search_log insert:', e?.message ?? e);
  }
}

async function d1RagIngestLog(env, { source, status, chunks }) {
  if (!env.DB) return;
  try {
    await env.DB.prepare(
      `INSERT INTO rag_ingest_log (object_key, status, chunk_count, triggered_by) VALUES (?,?,?,?)`
    )
      .bind(String(source || '').slice(0, 2000), status, Number(chunks) || 0, 'rag_ingest')
      .run();
  } catch (e) {
    console.warn('[rag] rag_ingest_log:', e?.message ?? e);
  }
}

function normalizeSearchRow(row, origin) {
  const similarity = Number(row.similarity ?? row.score ?? 0);
  const text =
    row.content ||
    row.summary ||
    row.body ||
    row.text ||
    '';
  const source = row.source || row.source_type || origin;
  return {
    id: row.id ?? row.session_id ?? null,
    content: text,
    source,
    title: row.title ?? null,
    similarity,
    _origin: origin,
  };
}

function mergeDedupeSort(rows) {
  const byHash = new Map();
  for (const r of rows) {
    const h = unifiedRagContentHash(r.content || JSON.stringify(r));
    const prev = byHash.get(h);
    if (!prev || r.similarity > prev.similarity) byHash.set(h, r);
  }
  return Array.from(byHash.values()).sort((a, b) => b.similarity - a.similarity);
}

/**
 * Internal unified search (Hyperdrive RPCs + OpenAI embed).
 */
export async function runUnifiedRagQuery(env, { query, tenantId, threshold, limit, includeSessions }) {
  const agentId = ragAgentId(env);
  if (!agentId) {
    return { results: [], error: 'RAG_AGENT_ID not configured' };
  }
  const q = String(query || '').trim();
  if (!q) return { results: [], error: 'empty query' };

  let vec;
  try {
    vec = await openaiCreateEmbedding(env, q);
  } catch (e) {
    const msg = e?.message ?? String(e);
    console.warn('[rag] runUnifiedRagQuery embed:', msg);
    return { results: [], error: msg };
  }
  const vecLit = vectorLiteral(vec);
  const dim = vec.length;
  if (!Number.isFinite(dim) || dim < 1 || dim > 16000) {
    return { results: [], error: 'invalid embedding dimensions' };
  }
  const vecSqlType = `vector(${dim})`;

  const lim = Math.min(Math.max(1, limit || 10), 50);
  const thr = typeof threshold === 'number' ? threshold : 0.7;

  const sqlCtx = `SELECT * FROM public.search_all_context($1::${vecSqlType}, $2::double precision, $3::integer, $4::text)`;
  const sqlSess = `SELECT * FROM public.match_session_summaries($1::${vecSqlType}, $2::text, $3::text, $4::double precision, $5::integer)`;

  const loadCtxRows = async () => {
    try {
      return await withPg(env, async (client) => {
        const res = await client.query(sqlCtx, [vecLit, thr, lim, agentId]);
        return res.rows || [];
      });
    } catch (e) {
      console.warn('[rag] search_all_context failed:', e?.message ?? e);
      return [];
    }
  };

  const loadSessRows = async () => {
    if (!includeSessions || !tenantId) return [];
    try {
      return await withPg(env, async (client) => {
        const res = await client.query(sqlSess, [vecLit, tenantId, agentId, thr, 5]);
        return res.rows || [];
      });
    } catch (e) {
      console.warn('[rag] match_session_summaries failed:', e?.message ?? e);
      return [];
    }
  };

  // Timeout guard — Hyperdrive hangs kill the entire chat pipeline without this
  const _ragMs = 3000;
  const _raceRag = (fn) => Promise.race([
    fn(),
    new Promise((_, rej) => setTimeout(() => rej(new Error('rag_timeout')), _ragMs)),
  ]);
  const [ctxRows, sessRows] = await Promise.all([
    _raceRag(loadCtxRows).catch(() => []),
    _raceRag(loadSessRows).catch(() => []),
  ]);
  const merged = [
    ...(ctxRows || []).map((r) => normalizeSearchRow(r, 'context')),
    ...(sessRows || []).map((r) => normalizeSearchRow(r, 'session')),
  ];
  const results = mergeDedupeSort(merged);
  return { results, embeddingDims: vec.length };
}

/**
 * Agent-facing RAG (replaces Vectorize / D1 chunk leg).
 */
export async function unifiedRagSearch(env, query, opts = {}) {
  const q = String(query || '').trim();
  if (!q || !env.HYPERDRIVE?.connectionString || !env.OPENAI_API_KEY) {
    return { matches: [], results: [], count: 0, _error: 'missing_bindings' };
  }
  const topK = Math.min(Math.max(1, opts.topK || 8), 24);
  const _t0 = Date.now();
  const tenantId = opts.tenantId != null && String(opts.tenantId).trim() !== '' ? String(opts.tenantId).trim() : null;
  const workspaceId =
    opts.workspaceId != null && String(opts.workspaceId).trim() !== '' ? String(opts.workspaceId).trim() : null;
  const sessionId =
    opts.sessionId != null && String(opts.sessionId).trim() !== '' ? String(opts.sessionId).trim() : null;
  const reqLimit = Math.max(topK, 10);
  const { results, error, embeddingDims } = await runUnifiedRagQuery(env, {
    query: q,
    tenantId,
    threshold: 0.7,
    limit: reqLimit,
    includeSessions: true,
  });
  const latencyMs = Date.now() - _t0;
  if (error) {
    return { matches: [], results: [], count: 0, _error: error };
  }
  const sliced = results.slice(0, topK);

  if (tenantId) {
    const sims = sliced.map((r) => r.similarity).filter((n) => Number.isFinite(n));
    const topSim = sims.length ? Math.max(...sims) : null;
    const avgSim = sims.length ? sims.reduce((a, b) => a + b, 0) / sims.length : null;
    const sourcesHit = [...new Set(sliced.map((r) => String(r.source || '')).filter(Boolean))];
    await logSemanticSearch(env, {
      searchFn: 'unified_rag_search',
      tenantId,
      sessionId,
      queryPreview: q,
      matchThreshold: 0.7,
      matchCountRequested: reqLimit,
      matchCountReturned: sliced.length,
      topSimilarity: topSim,
      avgSimilarity: avgSim,
      sourcesHit,
      latencyMs,
      metadata: {
        workspace_id: workspaceId,
        embed_model: ragEmbeddingModel(env) || null,
        embedding_dims: embeddingDims ?? null,
        rag_documents_project_id: ragDocumentsProjectId(env) || null,
      },
    });
  }

  return {
    matches: sliced.map((x) => {
      const tag = x.source ? `[${x.source}] ` : '';
      return `${tag}${x.content || ''}`.trim();
    }),
    results: sliced.map((x) => ({
      text: x.content,
      source: x.id,
      source_type: x._origin === 'session' ? 'supabase_session_summaries' : `supabase_${x.source || 'context'}`,
      score: Math.round(x.similarity * 1000) / 1000,
    })),
    count: sliced.length,
    _meta: { duration_ms: latencyMs },
  };
}

export function chunkMarkdown(text, maxChars = RAG_CHUNK_MAX_CHARS, overlap = RAG_CHUNK_OVERLAP) {
  const chunks = [];
  const sections = text.split(/(?=^##?\s)/m).map((s) => s.trim()).filter(Boolean);
  for (const section of sections) {
    if (section.length <= maxChars) {
      chunks.push(section);
      continue;
    }
    let start = 0;
    while (start < section.length) {
      const end = Math.min(start + maxChars, section.length);
      const slice = section.slice(start, end);
      if (slice.trim()) chunks.push(slice.trim());
      start = end - (end < section.length ? overlap : 0);
    }
  }
  return chunks.length ? chunks : [text.slice(0, maxChars)];
}

export async function compactAgentChatsToR2(env) {
  if (!env.DB || !env.R2) return { error: 'DB or R2 missing' };
  const cutoff = Math.floor(Date.now() / 1000) - RAG_COMPACT_HOURS * 3600;
  const out = await env.DB.prepare(`SELECT conversation_id, role, content FROM agent_messages WHERE created_at < ?`)
    .bind(cutoff)
    .all();
  const rows = out?.results || [];
  return { conversations_compacted: rows.length };
}

/**
 * POST /api/rag/ingest | /api/rag/search | /api/rag/sync | /api/search (POST)
 */
export async function handleRagApi(request, url, env, _ctx) {
  const path = url.pathname.replace(/\/$/, '') || '/';
  const method = request.method;

  if (method === 'OPTIONS') {
    return new Response(null, { status: 204, headers: { 'Access-Control-Allow-Origin': '*' } });
  }

  try {
    if (path === '/api/search' && method === 'POST') {
      return handleRagSearchRoute(request, env);
    }
    if (path === '/api/rag/ingest' && method === 'POST') {
      return handleRagIngest(request, env);
    }
    if (path === '/api/rag/search' && method === 'POST') {
      return handleRagSearchRoute(request, env);
    }
    if (path === '/api/rag/sync' && method === 'POST') {
      return handleRagSync(request, env);
    }
    return jsonResponse({ error: 'Not found' }, 404);
  } catch (e) {
    console.warn('[rag]', e?.message ?? e);
    return jsonResponse({ error: e?.message || 'RAG error' }, 500);
  }
}

async function handleRagIngest(request, env) {
  const rawBody = await request.text();
  const sig =
    request.headers.get('x-supabase-signature') || request.headers.get('X-Supabase-Signature') || '';
  const isWebhook = !!sig;
  if (isWebhook) {
    const secret = env.SUPABASE_WEBHOOK_SECRET;
    if (!secret || !(await verifySupabaseWebhookSignature(secret, rawBody, sig))) {
      return jsonResponse({ error: 'Invalid webhook signature' }, 401);
    }
  } else {
    const user = await getAuthUser(request, env);
    if (!user) return jsonResponse({ error: 'Unauthorized' }, 401);
  }

  let body;
  try {
    body = JSON.parse(rawBody || '{}');
  } catch {
    return jsonResponse({ error: 'Invalid JSON' }, 400);
  }

  const record = body.record || body;
  const content = String(record.content ?? body.content ?? '').trim();
  const source = String(record.source ?? body.source ?? '').trim();
  const title = String(record.title ?? body.title ?? (source || 'untitled')).slice(0, 500);
  const metadata =
    typeof record.metadata === 'object' && record.metadata !== null
      ? record.metadata
      : typeof body.metadata === 'object' && body.metadata !== null
        ? body.metadata
        : {};

  if (!content || !source) {
    return jsonResponse({ error: 'content and source required' }, 400);
  }

  const projectId = ragDocumentsProjectId(env);
  if (!projectId) return jsonResponse({ error: 'RAG_DOCUMENTS_PROJECT_ID not configured' }, 503);

  const dims = ragEmbeddingDims(env);
  if (!Number.isFinite(dims)) return jsonResponse({ error: 'RAG_EMBEDDING_DIMENSIONS not configured' }, 503);

  try {
    const embedding = await openaiCreateEmbedding(env, content);
    await upsertDocument(env, { source, title, content, embedding, projectId, metadata });

    const folder = resolveAutoragFolder(env, metadata);
    const r2Key = `${folder}${safeObjectSuffix(source)}.txt`;
    try {
      await r2PutObjectText(env, r2Key, content);
    } catch (e) {
      console.warn('[rag] R2 put skipped:', e?.message ?? e);
    }

    await d1RagIngestLog(env, { source, status: 'success', chunks: 1 });

    return jsonResponse({ ok: true, source, dims: embedding.length });
  } catch (e) {
    await d1RagIngestLog(env, { source, status: `error:${String(e?.message || e).slice(0, 80)}`, chunks: 0 });
    throw e;
  }
}

async function handleRagSearchRoute(request, env) {
  const user = await getAuthUser(request, env);
  if (!user) return jsonResponse({ error: 'Unauthorized' }, 401);

  const body = await request.json().catch(() => ({}));
  const query = String(body.query || '').trim();
  if (!query) return jsonResponse({ error: 'query required' }, 400);

  const threshold = typeof body.threshold === 'number' ? body.threshold : 0.7;
  const limit = typeof body.limit === 'number' ? body.limit : 10;
  const includeSessions = !!body.include_sessions;
  let tenantId = String(body.tenant_id || '').trim() || null;
  if (!tenantId && user.tenant_id) tenantId = String(user.tenant_id).trim();
  if (!tenantId && user.id) {
    const fromDb = await fetchAuthUserTenantId(env, user.id);
    if (fromDb) tenantId = fromDb;
  }

  const tSearch = Date.now();
  const { results, error: searchErr, embeddingDims } = await runUnifiedRagQuery(env, {
    query,
    tenantId,
    threshold,
    limit,
    includeSessions,
  });
  const latencyMs = Date.now() - tSearch;
  if (searchErr) return jsonResponse({ error: searchErr }, searchErr === 'empty query' ? 400 : 503);

  const sims = results.map((r) => r.similarity).filter((n) => Number.isFinite(n));
  const topSim = sims.length ? Math.max(...sims) : null;
  const avgSim = sims.length ? sims.reduce((a, b) => a + b, 0) / sims.length : null;
  const sourcesHit = [...new Set(results.map((r) => String(r.source || '')).filter(Boolean))];

  await logSemanticSearch(env, {
    searchFn: 'api.rag.search',
    tenantId,
    sessionId: user.session_id ?? null,
    queryPreview: query,
    matchThreshold: threshold,
    matchCountRequested: limit,
    matchCountReturned: results.length,
    topSimilarity: topSim,
    avgSimilarity: avgSim,
    sourcesHit,
    latencyMs,
    metadata: {
      include_sessions: includeSessions,
      embed_model: ragEmbeddingModel(env) || null,
      embedding_dims: embeddingDims ?? null,
      rag_documents_project_id: ragDocumentsProjectId(env) || null,
    },
  });

  return jsonResponse({
    ok: true,
    results,
    count: results.length,
    query_preview: query.slice(0, 100),
  });
}

async function handleRagSync(request, env) {
  if (!verifyInternalSecret(request, env)) {
    return jsonResponse({ error: 'Unauthorized' }, 401);
  }

  const projectId = ragDocumentsProjectId(env);
  if (!projectId) return jsonResponse({ error: 'RAG_DOCUMENTS_PROJECT_ID not configured' }, 503);

  let keys;
  try {
    keys = await r2ListAllObjectKeys(env);
  } catch (e) {
    return jsonResponse({ ok: false, error: e?.message || 'list failed' }, 500);
  }

  const synced = [];
  const skipped = [];
  const errors = [];

  const pending = [];
  for (const key of keys) {
    if (!key || key.endsWith('/')) continue;
    pending.push(key);
  }

  const batchSize = 10;
  for (let i = 0; i < pending.length; i += batchSize) {
    const batch = pending.slice(i, i + batchSize);
    await Promise.all(
      batch.map(async (sourceKey) => {
        try {
          const exists = await documentSourceExists(env, sourceKey, projectId);
          if (exists) {
            skipped.push(sourceKey);
            return;
          }
          const text = await r2GetObjectText(env, sourceKey);
          const embedding = await openaiCreateEmbedding(env, text);
          const title = sourceKey.split('/').pop() || sourceKey;
          await upsertDocument(env, {
            source: sourceKey,
            title,
            content: text,
            embedding,
            projectId,
            metadata: { folder: sourceKey.includes('/') ? `${sourceKey.slice(0, sourceKey.lastIndexOf('/') + 1)}` : 'knowledge/' },
          });
          synced.push(sourceKey);
          await d1RagIngestLog(env, { source: sourceKey, status: 'success', chunks: 1 });
        } catch (e) {
          errors.push({ key: sourceKey, error: e?.message || String(e) });
        }
      })
    );
  }

  return jsonResponse({ ok: true, synced: synced.length, skipped: skipped.length, errors });
}

/**
 * Insert one curated row into `public.agent_memory` with an OpenAI embedding (same model/dims as RAG).
 * Requires HYPERDRIVE, OPENAI_API_KEY, OPENAI_API_BASE_URL, RAG_OPENAI_EMBEDDING_MODEL, RAG_EMBEDDING_DIMENSIONS.
 *
 * @param {any} env
 * @param {{
 *   content: string,
 *   session_id: string,
 *   role?: string,
 *   agent_id?: string,
 *   metadata?: Record<string, unknown>,
 *   workspace_id?: string | null,
 *   tenant_id?: string | null,
 *   user_id?: string | null,
 * }} params
 * @returns {Promise<{ id: string, embedding_dims: number, embed_model: string }>}
 */
export async function insertCuratedAgentMemory(env, params) {
  const content = String(params.content || '').trim();
  if (!content) throw new Error('content required');
  const session_id = String(params.session_id || '').trim();
  if (!session_id) throw new Error('session_id required');

  const roleRaw = String(params.role || 'assistant').toLowerCase();
  if (roleRaw !== 'user' && roleRaw !== 'assistant') {
    throw new Error('role must be user or assistant');
  }
  const agent_id = String(params.agent_id || 'agent-sam').trim() || 'agent-sam';
  const metadata =
    params.metadata && typeof params.metadata === 'object' && params.metadata !== null && !Array.isArray(params.metadata)
      ? params.metadata
      : {};

  const workspace_id =
    params.workspace_id != null && String(params.workspace_id).trim() !== ''
      ? String(params.workspace_id).trim()
      : null;
  const tenant_id =
    params.tenant_id != null && String(params.tenant_id).trim() !== '' ? String(params.tenant_id).trim() : null;
  const user_id =
    params.user_id != null && String(params.user_id).trim() !== '' ? String(params.user_id).trim() : null;

  const embed_model = ragEmbeddingModel(env);
  const expectedDims = ragEmbeddingDims(env);
  if (!embed_model) throw new Error('RAG_OPENAI_EMBEDDING_MODEL not configured');
  if (!Number.isFinite(expectedDims)) throw new Error('RAG_EMBEDDING_DIMENSIONS not configured');

  const embedding = await openaiCreateEmbedding(env, content);
  const dims = embedding.length;
  if (dims !== expectedDims) {
    throw new Error(`embedding length ${dims} does not match RAG_EMBEDDING_DIMENSIONS (${expectedDims})`);
  }

  const vecLit = vectorLiteral(embedding);

  return await withPg(env, async (client) => {
    const ins = await client.query(
      `INSERT INTO public.agent_memory (
        session_id, agent_id, role, content, metadata,
        embedding, workspace_id, embed_model, tenant_id, user_id
      ) VALUES ($1, $2, $3, $4, $5::jsonb, $6::vector, $7, $8, $9, $10)
      RETURNING id`,
      [
        session_id,
        agent_id,
        roleRaw,
        content,
        metadata,
        vecLit,
        workspace_id,
        embed_model,
        tenant_id,
        user_id,
      ],
    );
    const id = ins.rows?.[0]?.id;
    if (!id) throw new Error('insert returned no id');

    const verify = await client.query(
      `SELECT vector_dims(embedding) AS dims FROM public.agent_memory WHERE id = $1::uuid`,
      [id],
    );
    const vd = verify.rows?.[0]?.dims;
    if (vd != null && Number(vd) !== expectedDims) {
      throw new Error(`vector_dims check failed: got ${vd}, expected ${expectedDims}`);
    }

    return {
      id: String(id),
      embedding_dims: dims,
      embed_model,
    };
  });
}

/**
 * Semantic-only search on `public.agent_memory` (cosine distance via pgvector).
 * Unlike `search_agent_memory`, this does **not** require trigram `%` on query text,
 * so paraphrased questions still match.
 *
 * @param {any} env
 * @param {{
 *   query: string,
 *   workspace_id: string,
 *   tenant_id: string | null,
 *   user_id?: string | null,
 *   session_id?: string | null,
 *   limit?: number,
 * }} opts
 * @returns {Promise<{ embed_model: string, results: Array<Record<string, unknown>> }>}
 */
export async function searchCuratedAgentMemory(env, opts) {
  const query = String(opts.query || '').trim();
  if (!query) throw new Error('query required');
  const workspace_id = String(opts.workspace_id || '').trim();
  if (!workspace_id) throw new Error('workspace_id required');

  const tenant_id =
    opts.tenant_id != null && String(opts.tenant_id).trim() !== '' ? String(opts.tenant_id).trim() : null;
  const user_id =
    opts.user_id != null && String(opts.user_id).trim() !== '' ? String(opts.user_id).trim() : null;
  const session_id =
    opts.session_id != null && String(opts.session_id).trim() !== '' ? String(opts.session_id).trim() : null;

  let limit = Number(opts.limit);
  if (!Number.isFinite(limit) || limit < 1) limit = 10;
  if (limit > 50) limit = 50;

  const embed_model = ragEmbeddingModel(env);
  if (!embed_model) throw new Error('RAG_OPENAI_EMBEDDING_MODEL not configured');
  if (!Number.isFinite(ragEmbeddingDims(env))) throw new Error('RAG_EMBEDDING_DIMENSIONS not configured');

  const embedding = await openaiCreateEmbedding(env, query);
  const vecLit = vectorLiteral(embedding);

  return await withPg(env, async (client) => {
    const sql = `
      SELECT
        am.id,
        am.session_id,
        am.agent_id,
        am.role,
        am.content,
        am.metadata,
        am.created_at,
        am.tenant_id,
        am.workspace_id,
        am.user_id,
        (am.embedding <=> $1::vector)::double precision AS embedding_distance
      FROM public.agent_memory am
      WHERE am.embedding IS NOT NULL
        AND am.workspace_id = $2
        AND ($3::text IS NULL OR am.tenant_id = $3)
        AND ($4::text IS NULL OR am.user_id = $4 OR am.user_id IS NULL)
        AND ($5::text IS NULL OR am.session_id = $5)
      ORDER BY am.embedding <=> $1::vector
      LIMIT $6`;
    const { rows } = await client.query(sql, [vecLit, workspace_id, tenant_id, user_id, session_id, limit]);

    const results = (rows || []).map((r) => {
      const d = r.embedding_distance != null ? Number(r.embedding_distance) : NaN;
      const similarity = Number.isFinite(d) ? Math.max(0, Math.min(1, 1 - d)) : null;
      return {
        id: r.id,
        session_id: r.session_id,
        agent_id: r.agent_id,
        role: r.role,
        content: r.content,
        metadata: r.metadata,
        created_at: r.created_at,
        tenant_id: r.tenant_id,
        workspace_id: r.workspace_id,
        user_id: r.user_id,
        embedding_distance: r.embedding_distance,
        similarity,
      };
    });

    return { embed_model, results };
  });
}

/**
 * POST /api/agent/memory/sync — Supabase webhook: embed new/updated rows.
 */
export async function handleAgentMemorySync(request, env) {
  if (request.method !== 'POST') return jsonResponse({ error: 'Method not allowed' }, 405);
  const rawBody = await request.text();
  const sig =
    request.headers.get('x-supabase-signature') || request.headers.get('X-Supabase-Signature') || '';
  const secret = env.SUPABASE_WEBHOOK_SECRET;
  if (!secret || !(await verifySupabaseWebhookSignature(secret, rawBody, sig))) {
    return jsonResponse({ error: 'Invalid webhook signature' }, 401);
  }

  let body;
  try {
    body = JSON.parse(rawBody || '{}');
  } catch {
    return jsonResponse({ error: 'Invalid JSON' }, 400);
  }

  const record = body.record || body;
  const id = record.id;
  const content = String(record.content || '').trim();
  if (!id || !content) {
    return jsonResponse({ error: 'record.id and record.content required' }, 400);
  }

  const emb = record.embedding;
  const needsEmbedding =
    emb == null || (Array.isArray(emb) && emb.length === 0) || (typeof emb === 'string' && !emb.trim());

  if (!needsEmbedding) {
    await d1RagIngestLog(env, { source: `agent_memory:${id}`, status: 'skipped_has_embedding', chunks: 0 });
    return jsonResponse({ ok: true });
  }

  try {
    const embedding = await openaiCreateEmbedding(env, content);
    const vecLit = vectorLiteral(embedding);
    await withPg(env, async (client) => {
      await client.query(`UPDATE public.agent_memory SET embedding = $1::vector WHERE id = $2::uuid`, [
        vecLit,
        id,
      ]);
    });
    await d1RagIngestLog(env, { source: `agent_memory:${id}`, status: 'success', chunks: 1 });
    return jsonResponse({ ok: true });
  } catch (e) {
    await d1RagIngestLog(env, {
      source: `agent_memory:${id}`,
      status: `error:${String(e?.message || e).slice(0, 80)}`,
      chunks: 0,
    });
    return jsonResponse({ error: e?.message || 'sync failed' }, 500);
  }
}

/**
 * Strict, awaited Supabase sync for Agent Sam workflow runs (server-side only).
 * Schema: agentsam.workflow_runs via PostgREST (Accept-Profile / Content-Profile: agentsam).
 */

export const AGENTSAM_WORKFLOW_RUNS_TABLE = 'agentsam_workflow_runs';

const WORKFLOW_RUNS_PATH = '/rest/v1/workflow_runs';

/** @param {import('@cloudflare/workers-types').D1Database} db */
async function pragmaAgentsamWorkflowRunsColumns(db) {
  try {
    const { results } = await db.prepare(`PRAGMA table_info(${AGENTSAM_WORKFLOW_RUNS_TABLE})`).all();
    return new Set((results || []).map((r) => String(r.name || '').toLowerCase()));
  } catch {
    return new Set();
  }
}

/**
 * Reflect Supabase mirror outcome on the D1 workflow run row (optional columns for older DBs).
 * @param {any} env
 * @param {string} d1RunId
 * @param {{ ok: boolean, supabaseRunId?: string|null, error?: string|null }} outcome
 */
export async function patchD1WorkflowRunSupabaseMirrorState(env, d1RunId, outcome) {
  const db = env?.DB;
  const rid = String(d1RunId || '').trim();
  if (!db || !rid) return;
  const cols = await pragmaAgentsamWorkflowRunsColumns(db);
  const fragments = [];
  const binds = [];

  if (cols.has('updated_at')) {
    fragments.push(`updated_at = datetime('now')`);
  }

  if (outcome.ok) {
    if (cols.has('supabase_sync_status')) fragments.push(`supabase_sync_status = 'synced'`);
    if (cols.has('supabase_sync_error')) fragments.push(`supabase_sync_error = NULL`);
    if (cols.has('supabase_synced_at')) fragments.push(`supabase_synced_at = datetime('now')`);
    const sid = outcome.supabaseRunId != null ? String(outcome.supabaseRunId).trim() : '';
    if (sid && cols.has('supabase_run_id')) {
      fragments.push(`supabase_run_id = ?`);
      binds.push(sid);
    }
    if (cols.has('supabase_sync_attempts')) {
      fragments.push(`supabase_sync_attempts = COALESCE(supabase_sync_attempts, 0) + 1`);
    }
  } else {
    const msg = String(outcome.error || 'supabase_sync_failed').slice(0, 8000);
    if (cols.has('supabase_sync_status')) fragments.push(`supabase_sync_status = 'failed'`);
    if (cols.has('supabase_sync_error')) {
      fragments.push(`supabase_sync_error = ?`);
      binds.push(msg);
    }
    if (cols.has('supabase_sync_attempts')) {
      fragments.push(`supabase_sync_attempts = COALESCE(supabase_sync_attempts, 0) + 1`);
    }
  }

  if (!fragments.length) return;
  binds.push(rid);
  const sql = `UPDATE ${AGENTSAM_WORKFLOW_RUNS_TABLE} SET ${fragments.join(', ')} WHERE id = ?`;
  try {
    await db.prepare(sql).bind(...binds).run();
  } catch (e) {
    console.warn('[agentsam-supabase-sync] patchD1WorkflowRunSupabaseMirrorState', e?.message ?? e);
  }
}

/** @param {string} text */
function parseSupabaseRpcWorkflowRunId(text) {
  const raw = String(text || '').trim();
  if (!raw) return null;
  try {
    const j = JSON.parse(raw);
    if (j == null) return null;
    if (typeof j === 'string' && j) return j;
    if (typeof j === 'number' && Number.isFinite(j)) return String(j);
    if (typeof j === 'object' && !Array.isArray(j) && j.id != null) return String(j.id);
    if (Array.isArray(j) && j.length) {
      const x = j[0];
      if (typeof x === 'string') return x;
      if (x && typeof x === 'object' && x.id != null) return String(x.id);
    }
  } catch {
    // non-JSON body (rare)
  }
  return null;
}

/**
 * @param {import('@cloudflare/workers-types').D1Result} result
 * @param {string} label
 */
export function assertD1Write(result, label) {
  if (result == null) throw new Error(`[${label}] D1: no result`);
  if (result.success === false) throw new Error(`[${label}] D1: success=false`);
  const changes = result.meta?.changes ?? 0;
  if (changes < 1) throw new Error(`[${label}] D1: expected ≥1 row changed, got ${changes}`);
}

function supabaseRestBase(env) {
  const raw = env?.SUPABASE_URL;
  if (!raw || !String(raw).trim()) throw new Error('SUPABASE_URL is not configured');
  return String(raw).replace(/\/$/, '');
}

function supabaseServiceRole(env) {
  const key = env?.SUPABASE_SERVICE_ROLE_KEY;
  if (!key || !String(key).trim()) throw new Error('SUPABASE_SERVICE_ROLE_KEY is not configured');
  return String(key).trim();
}

function supabaseHeaders(env, extra = {}) {
  const key = supabaseServiceRole(env);
  return {
    apikey: key,
    Authorization: `Bearer ${key}`,
    'Content-Type': 'application/json',
    Prefer: 'return=representation',
    'Accept-Profile': 'agentsam',
    'Content-Profile': 'agentsam',
    ...extra,
  };
}

/**
 * Insert a row in agentsam.workflow_runs. Returns the created row (must include id).
 * @param {any} env
 * @param {Record<string, unknown>} runPayload
 */
export async function createSupabaseWorkflowRun(env, runPayload) {
  const base = supabaseRestBase(env);
  const res = await fetch(`${base}${WORKFLOW_RUNS_PATH}`, {
    method: 'POST',
    headers: supabaseHeaders(env),
    body: JSON.stringify(runPayload),
  });
  const text = await res.text();
  if (!res.ok) {
    throw new Error(`Supabase workflow_runs insert failed HTTP ${res.status}: ${text.slice(0, 4000)}`);
  }
  let json;
  try {
    json = text ? JSON.parse(text) : [];
  } catch (e) {
    throw new Error(`Supabase insert: invalid JSON: ${String(e?.message || e)}`);
  }
  const row = Array.isArray(json) ? json[0] : json;
  if (!row || row.id == null || String(row.id).trim() === '') {
    throw new Error('Supabase insert returned no id');
  }
  return row;
}

/**
 * PATCH agentsam.workflow_runs by primary key id.
 * @param {any} env
 * @param {string} supabaseRunId
 * @param {Record<string, unknown>} patch
 */
export async function updateSupabaseWorkflowRun(env, supabaseRunId, patch) {
  const id = String(supabaseRunId || '').trim();
  if (!id) throw new Error('updateSupabaseWorkflowRun: supabaseRunId required');
  const base = supabaseRestBase(env);
  const url = `${base}${WORKFLOW_RUNS_PATH}?id=eq.${encodeURIComponent(id)}`;
  const res = await fetch(url, {
    method: 'PATCH',
    headers: supabaseHeaders(env),
    body: JSON.stringify(patch),
  });
  const text = await res.text();
  if (!res.ok) {
    throw new Error(`Supabase workflow_runs PATCH failed HTTP ${res.status}: ${text.slice(0, 4000)}`);
  }
  if (res.status === 204) {
    return { ok: true, rows: [] };
  }
  let json;
  try {
    json = text ? JSON.parse(text) : [];
  } catch (e) {
    throw new Error(`Supabase PATCH: invalid JSON: ${String(e?.message || e)}`);
  }
  if (Array.isArray(json) && json.length === 0) {
    throw new Error('Supabase PATCH returned no updated rows');
  }
  return Array.isArray(json) ? json[0] : json;
}

/**
 * After a successful Supabase insert: store id + synced on D1.
 * @param {any} env
 * @param {string} d1RunId
 * @param {string} supabaseRunId
 */
export async function markWorkflowRunSupabaseSynced(env, d1RunId, supabaseRunId) {
  const db = env?.DB;
  if (!db) throw new Error('markWorkflowRunSupabaseSynced: DB not configured');
  const sid = String(supabaseRunId ?? '').trim();
  let result;
  if (sid) {
    result = await db
      .prepare(
        `UPDATE ${AGENTSAM_WORKFLOW_RUNS_TABLE}
         SET supabase_run_id = ?,
             supabase_sync_status = 'synced',
             supabase_synced_at = datetime('now'),
             supabase_sync_error = NULL,
             supabase_sync_attempts = COALESCE(supabase_sync_attempts, 0) + 1
         WHERE id = ?`,
      )
      .bind(sid, d1RunId)
      .run();
  } else {
    result = await db
      .prepare(
        `UPDATE ${AGENTSAM_WORKFLOW_RUNS_TABLE}
         SET supabase_sync_status = 'synced',
             supabase_synced_at = datetime('now'),
             supabase_sync_error = NULL,
             supabase_sync_attempts = COALESCE(supabase_sync_attempts, 0) + 1
         WHERE id = ?`,
      )
      .bind(d1RunId)
      .run();
  }
  assertD1Write(result, 'markWorkflowRunSupabaseSynced');
}

/**
 * Record Supabase sync failure on the D1 run row.
 * @param {any} env
 * @param {string} d1RunId
 * @param {string} error
 */
const SUPABASE_RPC_FALLBACK_ORIGIN = 'https://dpmuvynqixblxsilnlut.supabase.co';

function restOriginForRpc(env) {
  try {
    return supabaseRestBase(env);
  } catch {
    return SUPABASE_RPC_FALLBACK_ORIGIN.replace(/\/$/, '');
  }
}

/**
 * Fire-and-forget analytics sync to Supabase Postgres RPC (non-fatal; D1 remains source of truth).
 * @param {any} env
 * @param {Record<string, unknown>} run — D1 agentsam_workflow_runs row or compatible object
 */
export async function syncWorkflowRunToSupabase(env, run) {
  const key = env?.SUPABASE_SERVICE_ROLE_KEY;
  const db = env?.DB;
  if (!key || !run?.id || !db) return;
  const secToIso = (t) => {
    if (t == null || t === '') return null;
    const n = Number(t);
    if (!Number.isFinite(n)) return null;
    return new Date(n < 1e12 ? n * 1000 : n).toISOString();
  };
  let toolCallsCount = run.tool_calls_count != null ? Number(run.tool_calls_count) : null;
  if (toolCallsCount == null || !Number.isFinite(toolCallsCount)) {
    try {
      const raw = run.step_results_json;
      const arr = typeof raw === 'string' ? JSON.parse(raw || '[]') : raw;
      if (Array.isArray(arr)) toolCallsCount = arr.length;
    } catch {
      toolCallsCount = 0;
    }
  }
  if (!Number.isFinite(toolCallsCount)) toolCallsCount = 0;

  let status = run.status != null ? String(run.status) : '';
  if (status === 'success') status = 'completed';

  try {
    const supabaseRow = await createSupabaseWorkflowRun(env, {
      d1_workflow_id: run.id,
      workflow_key: run.workflow_key ?? '',
      display_name: run.display_name ?? '',
      tenant_id: run.tenant_id ?? '',
      workspace_id:
        run.workspace_id ||
        (env.DEFAULT_WORKSPACE_ID != null && String(env.DEFAULT_WORKSPACE_ID).trim() !== ''
          ? String(env.DEFAULT_WORKSPACE_ID).trim()
          : ''),
      status: status || 'unknown',
      started_at: secToIso(run.started_at),
      completed_at: secToIso(run.completed_at),
      duration_ms: run.duration_ms != null ? Number(run.duration_ms) : null,
      cost_usd: run.cost_usd != null ? Number(run.cost_usd) : 0,
      input_tokens: run.input_tokens != null ? Number(run.input_tokens) : 0,
      output_tokens: run.output_tokens != null ? Number(run.output_tokens) : 0,
      tool_calls_count: toolCallsCount,
      error_message: run.error_message ?? null,
      model_id: run.model_used ?? run.model_id ?? null,
    });

    const supabaseRunId = supabaseRow?.id != null ? String(supabaseRow.id) : null;
    await patchD1WorkflowRunSupabaseMirrorState(env, run.id, { ok: true, supabaseRunId });
  } catch (e) {
    await patchD1WorkflowRunSupabaseMirrorState(env, run.id, {
      ok: false,
      error: e?.message != null ? String(e.message) : String(e),
    });
  }
}

export async function markWorkflowRunSupabaseFailed(env, d1RunId, error) {
  const db = env?.DB;
  if (!db) throw new Error('markWorkflowRunSupabaseFailed: DB not configured');
  const msg = String(error || 'unknown error').slice(0, 8000);
  const result = await db
    .prepare(
      `UPDATE ${AGENTSAM_WORKFLOW_RUNS_TABLE}
       SET supabase_sync_status = 'failed',
           supabase_sync_error = ?,
           supabase_sync_attempts = COALESCE(supabase_sync_attempts, 0) + 1
       WHERE id = ?`,
    )
    .bind(msg, d1RunId)
    .run();
  assertD1Write(result, 'markWorkflowRunSupabaseFailed');
}

/**
 * src/core/memory.js
 *
 * Agent memory for prompt injection — single entry point: loadAgentMemoryForPrompt.
 *
 * Design:
 *  1. Skip entirely for short/command messages (< 6 words) — no DB hit
 *  2. KV cache per workspace/tenant, 3-minute TTL — warm path is one KV read
 *  3. Hard 2s Promise.race timeout — memory NEVER blocks the model call
 *  4. D1 agentsam_memory keyword match (fast, no embedding)
 *  5. Supabase search_all_context_logged via Hyperdrive (semantic, fires only for longer messages)
 *  6. No env.AI.run embedding call ever — that killed the Worker with CPU timeouts
 *
 * Thompson routing:
 *  writeRoutingMemoryPrior — called by applyRoutingArmUsageFeedback after each run
 *  to keep agentsam_model_routing_memory populated for cold-start priors.
 */

import { logSemanticSearch } from '../api/rag.js';
import { compactToolStatsCompacted } from './tool-stats-rollup.js';

const MEMORY_KV_TTL_SEC   = 180;   // 3 minutes
const MEMORY_TIMEOUT_MS   = 2000;  // hard cap — never blocks model call
const MIN_WORDS_FOR_RAG   = 6;     // skip semantic search for short messages
const SUPABASE_REST_FALLBACK = 'https://dpmuvynqixblxsilnlut.supabase.co';

// ─── Helpers ──────────────────────────────────────────────────────────────────

function supabaseOrigin(env) {
  const raw = env?.SUPABASE_URL && String(env.SUPABASE_URL).trim();
  return raw ? raw.replace(/\/$/, '') : SUPABASE_REST_FALLBACK;
}

function withTimeout(promise, ms) {
  return Promise.race([
    promise,
    new Promise((resolve) => setTimeout(() => resolve(null), ms)),
  ]);
}

function wordCount(s) {
  return s.trim().split(/\s+/).filter(Boolean).length;
}

function isSimpleCommand(msg) {
  return /^(pong|ping|hi|hello|hey|yes|no|ok|okay|sure|thanks|thx|test|help)[\s!?.]*$/i.test(
    msg.trim(),
  );
}

function formatD1MemoryBlock(rows) {
  if (!rows?.length) return '';
  const lines = rows.map((r) => {
    const t = String(r.memory_type || 'fact').toUpperCase();
    return `[${t}] ${r.key}: ${r.value}`;
  });
  return `\n## Agent Memory (${lines.length} items)\n${lines.join('\n')}\n`;
}

function formatSemanticBlock(rows) {
  if (!rows?.length) return '';
  const lines = rows
    .map((r) => {
      const sim = r.similarity != null ? `[${Number(r.similarity).toFixed(2)}] ` : '';
      const text = r.content ?? r.text ?? r.value ?? '';
      return text ? `- ${sim}${text}` : null;
    })
    .filter(Boolean);
  if (!lines.length) return '';
  return `\n## Semantic Context (${lines.length} items)\n${lines.join('\n')}\n`;
}

// ─── KV cache ─────────────────────────────────────────────────────────────────

function memoryKvKey(tenantId, workspaceId) {
  return `agentsam_memory:${tenantId}:${workspaceId || 'global'}`;
}

async function getCachedMemory(env, tenantId, workspaceId) {
  if (!env?.SESSION_CACHE) return null;
  try {
    const val = await env.SESSION_CACHE.get(memoryKvKey(tenantId, workspaceId));
    return val ?? null;
  } catch {
    return null;
  }
}

async function setCachedMemory(env, tenantId, workspaceId, value) {
  if (!env?.SESSION_CACHE || !value) return;
  try {
    await env.SESSION_CACHE.put(memoryKvKey(tenantId, workspaceId), value, {
      expirationTtl: MEMORY_KV_TTL_SEC,
    });
  } catch {
    // KV write failure must never break chat
  }
}

// ─── D1 agentsam_memory (keyword path, no embedding) ─────────────────────────

async function loadD1Memory(env, tenantId, workspaceId) {
  if (!env?.DB || !tenantId) return '';
  try {
    const wsClause = workspaceId
      ? `AND (workspace_id = ? OR workspace_id IS NULL OR TRIM(COALESCE(workspace_id,'')) = '')`
      : `AND (workspace_id IS NULL OR TRIM(COALESCE(workspace_id,'')) = '')`;
    const binds = workspaceId
      ? [String(tenantId), String(workspaceId)]
      : [String(tenantId)];

    const { results } = await env.DB.prepare(
      `SELECT id, key, value, memory_type, confidence, decay_score
       FROM agentsam_memory
       WHERE tenant_id = ? ${wsClause}
         AND decay_score > 0.3
         AND (expires_at IS NULL OR expires_at > unixepoch())
         AND value NOT LIKE '[STALE%'
       ORDER BY
         CASE memory_type
           WHEN 'error'      THEN 1
           WHEN 'decision'   THEN 2
           WHEN 'fact'       THEN 3
           WHEN 'skill'      THEN 4
           WHEN 'preference' THEN 5
           WHEN 'project'    THEN 6
           ELSE 7
         END,
         confidence DESC, decay_score DESC
       LIMIT 20`,
    )
      .bind(...binds)
      .all();

    const list = results || [];
    if (!list.length) return '';

    // Fire-and-forget recall count update
    const ids = list.map((r) => r.id).filter(Boolean);
    if (ids.length && env.DB) {
      const ph = ids.map(() => '?').join(',');
      env.DB.prepare(
        `UPDATE agentsam_memory
         SET recall_count    = recall_count + 1,
             last_recalled_at = unixepoch(),
             updated_at       = unixepoch()
         WHERE id IN (${ph})`,
      )
        .bind(...ids)
        .run()
        .catch(() => {});
    }

    return formatD1MemoryBlock(list);
  } catch (e) {
    console.warn('[memory] d1_load', e?.message ?? e);
    return '';
  }
}

// ─── Supabase search_all_context_logged (semantic, Hyperdrive) ────────────────

async function searchSupabaseContext(env, userMessage, tenantId, workspaceId, sessionId) {
  const key = env?.SUPABASE_SERVICE_ROLE_KEY;
  if (!key) return '';
  try {
    const url = `${supabaseOrigin(env)}/rest/v1/rpc/search_all_context_logged`;
    const body = JSON.stringify({
      p_query:        userMessage.slice(0, 1000),
      p_tenant_id:    tenantId,
      p_workspace_id: workspaceId || null,
      p_session_id:   sessionId   || null,
      p_match_count:  8,
      p_threshold:    0.72,
    });
    const res = await fetch(url, {
      method:  'POST',
      headers: {
        'Content-Type': 'application/json',
        Authorization:  `Bearer ${key}`,
        apikey:         key,
        Prefer:         'return=representation',
      },
      body,
    });
    if (!res.ok) return '';
    const json = await res.json().catch(() => []);
    return formatSemanticBlock(Array.isArray(json) ? json : []);
  } catch {
    return '';
  }
}

// ─── Main export ──────────────────────────────────────────────────────────────

/**
 * Primary entry point called by agent.js before every model dispatch.
 *
 * Returns a markdown block to append to the system prompt, or '' to skip.
 * Never throws. Never blocks longer than MEMORY_TIMEOUT_MS.
 */
export async function loadAgentMemoryForPrompt(env, tenantId, ctx = {}) {
  const userMessage  = ctx?.userMessage != null ? String(ctx.userMessage).trim() : '';
  const workspaceId  = ctx?.workspaceId  != null && String(ctx.workspaceId).trim()  !== '' ? String(ctx.workspaceId).trim()  : null;
  const sessionId    = ctx?.sessionId    != null && String(ctx.sessionId).trim()    !== '' ? String(ctx.sessionId).trim()    : null;

  // Fast exits — don't touch any DB
  if (!tenantId) return '';
  if (!userMessage || isSimpleCommand(userMessage)) return '';

  const isLongMessage = wordCount(userMessage) >= MIN_WORDS_FOR_RAG;

  // KV cache hit — one read, no D1 or Supabase
  const cached = await withTimeout(
    getCachedMemory(env, tenantId, workspaceId),
    300,
  );
  if (cached != null) return cached;

  // Race both sources against the hard timeout
  const work = async () => {
    const parts = await Promise.all([
      // D1 key/value facts — always fast
      loadD1Memory(env, tenantId, workspaceId),
      // Supabase semantic — only for longer messages
      isLongMessage
        ? searchSupabaseContext(env, userMessage, tenantId, workspaceId, sessionId)
        : Promise.resolve(''),
    ]);

    const d1Block   = parts[0] || '';
    const semBlock  = parts[1] || '';
    const combined  = [d1Block, semBlock].filter(Boolean).join('\n');

    // Write back to KV for next request (fire-and-forget)
    if (combined) {
      setCachedMemory(env, tenantId, workspaceId, combined).catch(() => {});
    }

    return combined || '';
  };

  try {
    return (await withTimeout(work(), MEMORY_TIMEOUT_MS)) || '';
  } catch {
    return '';
  }
}

/**
 * Raw D1-only memory load (no embedding, no timeout) — used by crons and non-chat paths.
 */
export async function loadAgentMemory(env, tenantId) {
  return loadD1Memory(env, tenantId, null);
}

// ─── Supabase recallSemanticMemory (kept for backward compat, non-chat paths) ─

export async function recallSemanticMemory(env, embedding, sessionId, agentId, workspaceId) {
  const key = env?.SUPABASE_SERVICE_ROLE_KEY;
  if (!key || !Array.isArray(embedding) || !embedding.length) return [];
  try {
    const res = await fetch(`${supabaseOrigin(env)}/rest/v1/rpc/match_agent_memory`, {
      method:  'POST',
      headers: {
        'Content-Type': 'application/json',
        Authorization:  `Bearer ${key}`,
        apikey:         key,
      },
      body: JSON.stringify({
        query_embedding: embedding,
        p_session_id:    sessionId   || null,
        p_agent_id:      agentId     || null,
        p_workspace_id:  workspaceId || null,
        p_limit:         10,
        p_threshold:     0.75,
      }),
    });
    if (!res.ok) return [];
    const json = await res.json().catch(() => []);
    return Array.isArray(json) ? json : [];
  } catch {
    return [];
  }
}

// ─── Thompson routing memory write-back ───────────────────────────────────────

/**
 * Called by applyRoutingArmUsageFeedback after every run to keep
 * agentsam_model_routing_memory populated for cold-start Thompson priors.
 *
 * Uses INSERT OR REPLACE with an Welford running average so each row stays
 * lightweight and never grows unbounded.
 */
export async function writeRoutingMemoryPrior(env, {
  workspaceId,
  taskType,
  modelKey,
  provider,
  success,
  latencyMs,
  costUsd,
}) {
  if (!env?.DB || !workspaceId || !taskType || !modelKey) return;
  try {
    const ws  = String(workspaceId).trim();
    const tt  = String(taskType).trim();
    const mk  = String(modelKey).trim();
    const pv  = provider ? String(provider).trim() : null;

    // Read existing row
    const existing = await env.DB.prepare(
      `SELECT success_rate, avg_latency_ms, avg_cost_usd, sample_n
       FROM agentsam_model_routing_memory
       WHERE workspace_id = ? AND task_type = ? AND model_key = ?
       LIMIT 1`,
    ).bind(ws, tt, mk).first().catch(() => null);

    const n         = Number(existing?.sample_n ?? 0);
    const newN      = n + 1;
    const successVal = success ? 1.0 : 0.0;

    // Welford incremental mean
    const prevSr  = Number(existing?.success_rate   ?? 0.5);
    const prevLat = Number(existing?.avg_latency_ms ?? latencyMs ?? 0);
    const prevCost= Number(existing?.avg_cost_usd   ?? costUsd   ?? 0);

    const newSr   = prevSr   + (successVal                   - prevSr)   / newN;
    const newLat  = latencyMs != null ? prevLat + (latencyMs - prevLat) / newN : prevLat;
    const newCost = costUsd   != null ? prevCost + (costUsd  - prevCost) / newN : prevCost;

    await env.DB.prepare(
      `INSERT INTO agentsam_model_routing_memory
         (workspace_id, task_type, model_key, provider,
          success_rate, avg_latency_ms, avg_cost_usd, sample_n,
          last_evaluated_at, updated_at)
       VALUES (?, ?, ?, ?, ?, ?, ?, ?, strftime('%Y-%m-%dT%H:%M:%fZ','now'), strftime('%Y-%m-%dT%H:%M:%fZ','now'))
       ON CONFLICT(task_type, model_key, workspace_id) DO UPDATE SET
         provider          = excluded.provider,
         success_rate      = excluded.success_rate,
         avg_latency_ms    = excluded.avg_latency_ms,
         avg_cost_usd      = excluded.avg_cost_usd,
         sample_n          = excluded.sample_n,
         last_evaluated_at = excluded.last_evaluated_at,
         updated_at        = excluded.updated_at`,
    ).bind(ws, tt, mk, pv, newSr, newLat, newCost, newN).run();
  } catch (e) {
    // Routing memory write must never break chat
    console.warn('[memory] writeRoutingMemoryPrior', e?.message ?? e);
  }
}

