export function normalizeToolName(toolName) {
    const n = String(toolName || '').trim();
    const aliases = {
        terminal_execute: 'terminal_run',
        run_command: 'terminal_run',
        bash: 'terminal_run',

        github_file: 'github_get_file',
        github_read: 'github_get_file',
        github_repo: 'github_repos',
        github_list_repos: 'github_repos',

        // Dashboard self-debug friendly aliases → existing CDT / browser MCP tools (no new D1 rows).
        browser_open_url: 'cdt_navigate_page',
        browser_get_dom_summary: 'cdt_take_snapshot',
        browser_click: 'cdt_click',
        browser_type: 'cdt_fill',
        browser_press: 'cdt_press_key',
        browser_get_console_errors: 'cdt_list_console_messages',
        browser_get_network_events: 'cdt_list_network_requests',
        browser_get_current_url: 'cdt_list_pages',
        browser_wait_for_text: 'cdt_wait_for',
        browser_eval_safe: 'cdt_evaluate_script',

        // ai-ops.js registers ai_complete / ai_compare / ai_embed (not agentsam_*).
        // Legacy or mistaken names route to the same handlers.
        agentsam_complete: 'ai_complete',
        agentsam_compare: 'ai_compare',
        agentsam_embed: 'ai_embed',
    };
    return aliases[n] || n;
}

/**
 * Universal Tool Dispatcher (Omni-Sam v2.0).
 * Routes 100+ model-requested tools to their modular production handlers.
 */
export async function runBuiltinTool(env, toolName, params, runContext = {}) {
    toolName = normalizeToolName(toolName);
    console.log(`[AI Dispatcher] Executing: ${toolName}`);

    // High-priority tools that normally require frontend approval gates
    const requiresApproval = [
        'cdt_evaluate_script', 'cdt_upload_file', 'd1_write', 
        'worker_deploy', 'resend_send_broadcast', 'resend_create_api_key',
        'meshyai_image_to_3d', 'meshyai_text_to_3d', 'agentsam_run_agent'
    ];

    if (requiresApproval.includes(toolName)) {
        console.warn(`[AI Dispatcher] Approval required tool detected: ${toolName}`);
    }

    switch (true) {
        // ── CATEGORY: browser / web (31 Tools) ───────────────────────────
        case toolName.startsWith('cdt_'):
        case toolName.startsWith('browser_'):
        case toolName === 'playwright_screenshot':
        case toolName === 'preview_in_browser':
        case toolName === 'web_search':
            return await webHandlers[toolName]?.(params, env) || await webHandlers.search_web?.(params, env);

        // ── CATEGORY: media / ui (13 Tools) ──────────────────────────────
        case toolName.startsWith('excalidraw_'):
        case toolName.startsWith('voxel_'):
        case toolName.startsWith('meshyai_'):
        case toolName.startsWith('imgx_'):
            return await mediaHandlers[toolName]?.(params, env);

        // ── CATEGORY: context / RAG (11 Tools) ───────────────────────────
        case toolName.startsWith('context_'):
        case toolName.startsWith('human_context_'):
        case toolName === 'knowledge_search':
        case toolName === 'rag_search':
        case toolName === 'attached_file_content':
            return await contextHandlers[toolName]?.(params, env);

        // ── CATEGORY: db (3 Tools) ───────────────────────────────────────
        case toolName.startsWith('d1_'):
            return await dbHandlers[toolName]?.(params, env);

        // ── CATEGORY: memory (4 Tools) ─────────────────────────────────────────
        case toolName.startsWith('memory_'):
            return await memoryHandlers[toolName]?.(params, env, runContext);

        // ── CATEGORY: deploy (5 Tools) ───────────────────────────────────────────────
        case toolName.startsWith('worker_'):
        case toolName === 'list_workers':
        case toolName === 'get_deploy_command':
        case toolName === 'get_worker_services':
            return await deployHandlers[toolName]?.(params, env);

        // ── CATEGORY: workflow (2 Tools) ─────────────────────────────────────────────
        case toolName === 'workflow_run_pipeline':
        case toolName === 'generate_daily_summary_email':
        case toolName === 'generate_execution_plan':
            return await workflowHandlers[toolName]?.(params, env);

        // ── CATEGORY: email / imessage / integrations / conversion (18 Tools) ──
        case toolName.startsWith('github_'):
            return await githubWorkerHandlers[toolName]?.(params, env);

        case toolName.startsWith('resend_'):
        case toolName.startsWith('imessage.'):
        case toolName.startsWith('cf_images_'):
        case toolName.startsWith('gdrive_'):
        case toolName.startsWith('cloudconvert_'):
            return await integrationsHandlers[toolName]?.(params, env) || await imessageTools[toolName]?.({ env, session: params.session }, params);

        // ── CATEGORY: storage (9 Tools) ──────────────────────────────────
        case toolName.startsWith('r2_'):
        case toolName.startsWith('workspace_'):
        case toolName === 'get_r2_url':
            return await storageHandlers[toolName]?.(params, env);

        // ── CATEGORY: platform / quality (4 Tools) ───────────────────────
        case toolName.startsWith('a11y_'):
        case toolName === 'platform_info':
        case toolName === 'list_clients':
            return await platformHandlers[toolName]?.(params, env);

        // ── CATEGORY: telemetry (3 Tools) ────────────────────────────────────────────
        case toolName.startsWith('telemetry_'):
            return await telemetryHandlers[toolName]?.(params, env);

        // ── CATEGORY: intelligence / llm ops (Workers AI + embeddings) ───
        case toolName.startsWith('ai_'):
        case toolName === 'agentsam_complete':
        case toolName === 'agentsam_compare':
        case toolName === 'agentsam_embed': {
            const key =
                toolName.startsWith('ai_')
                    ? toolName
                    : { agentsam_complete: 'ai_complete', agentsam_compare: 'ai_compare', agentsam_embed: 'ai_embed' }[
                          toolName
                      ];
            const out = key ? await aiOpsHandlers[key]?.(params, env) : undefined;
            return out ?? { error: `Tool integration for '${toolName}' not found.` };
        }

        // ── CATEGORY: agent (3 Tools) ────────────────────────────────────
        case toolName.startsWith('agentsam_'):
            return await agentHandlers[toolName]?.(params, env);

        // ── CATEGORY: terminal / execution (3 Tools) ──────────────────────
        case toolName === 'terminal_run':
        case toolName === 'terminal_execute':
        case toolName === 'run_command':
        case toolName === 'bash':
            return await termHandlers.run_command?.(params, env);

        case toolName === 'python_execute':
            return await python_execute(params, env);

        // ── CATEGORY: intelligence / llm ops (6 Tools) ──────────────────
        case toolName.startsWith('anthropic_cli'):
            return await anthropicCliHandlers[toolName]?.(params, env);
        case toolName.startsWith('anthropic_batch'):
            return await anthropicBatchHandlers[toolName]?.(params, env);

        default:
            return { error: `Tool integration for '${toolName}' not found.` };
    }
}

/**
 * Executes agentsam_workflow_nodes / agentsam_workflow_edges as a directed graph.
 * Persists state to agentsam_workflow_runs row by row.
 */
import { pragmaTableInfo } from './retention.js';
import { resolveCanonicalUserId } from '../api/auth.js';
import { insertExecutionDependencyGraphEdge } from '../api/command-run-telemetry.js';

const TIER_ORDER = ['micro', 'flash', 'standard', 'power', 'reasoning'];

const TRIGGER_TYPES_SAFE = new Set([
  'manual',
  'agent',
  'cursor',
  'github_push',
  'scheduled',
  'cicd',
  'deploy',
  'api',
  'smoke',
]);

/**
 * MCP catalog row that owns agentsam_workflow_nodes.workflow_id (D1 FK).
 * Prefers tenant + workspace match, then tenant-scoped, then platform-global rows.
 */
async function resolveMcpWorkflowRow(db, workflowKey, tenantId, workspaceId) {
  if (!db) return null;
  const key = String(workflowKey || '').trim();
  if (!key) return null;
  const tid = tenantId != null ? String(tenantId).trim() : '';
  const wid = workspaceId != null ? String(workspaceId).trim() : '';

  const first = async (sql, binds) =>
    db
      .prepare(sql)
      .bind(...binds)
      .first()
      .catch(() => null);

  if (tid && wid) {
    const exact = await first(
      `SELECT * FROM agentsam_mcp_workflows
       WHERE workflow_key = ? AND COALESCE(is_active, 1) = 1
         AND tenant_id = ? AND (workspace_id = ? OR workspace_id IS NULL)
       ORDER BY CASE WHEN workspace_id = ? THEN 0 ELSE 1 END, updated_at DESC
       LIMIT 1`,
      [key, tid, wid, wid],
    );
    if (exact) return exact;
  }
  if (tid) {
    const tenantRow = await first(
      `SELECT * FROM agentsam_mcp_workflows
       WHERE workflow_key = ? AND COALESCE(is_active, 1) = 1 AND tenant_id = ?
       ORDER BY (workspace_id IS NOT NULL) DESC, updated_at DESC
       LIMIT 1`,
      [key, tid],
    );
    if (tenantRow) return tenantRow;
  }
  return first(
    `SELECT * FROM agentsam_mcp_workflows
     WHERE workflow_key = ? AND COALESCE(is_active, 1) = 1
       AND tenant_id IS NULL AND workspace_id IS NULL
     ORDER BY updated_at DESC
     LIMIT 1`,
    [key],
  );
}

function normalizeTriggerType(raw) {
  const t = String(raw || 'agent').toLowerCase().trim();
  return TRIGGER_TYPES_SAFE.has(t) ? t : 'agent';
}

// ── Node type dispatchers ────────────────────────────────────────────

async function dispatchNode(env, node, input, runContext) {
  const { node_type: nodeType, handler_key: handlerKey } = node;
  const smoke = Boolean(input?.smoke);
  const hk = String(handlerKey || '').trim();

  if (hk) {
    try {
      const stepMod = await import('./agent-step.js');
      if (stepMod.isRegisteredAgentStepHandler?.(hk)) {
        return stepMod.agentChatStep(env, { handler_key: hk, input, runContext, node, smoke });
      }
    } catch (e) {
      console.warn('[workflow-graph] agent-step', e?.message ?? e);
    }
  }

  switch (nodeType) {
    case 'agent': {
      if (smoke) return { ok: true, output: { smoke: true, skipped: true, note: 'agent smoke short-circuit' } };
      try {
        const { dispatchComplete } = await import('./provider.js');

        // Derive task_type: prefer agentsam_workflows.default_task_type, then handler_key, then fallback
        const hkParts = String(handlerKey || '').split('.');
        const taskType =
          runContext?.workflowMeta?.default_task_type
          || hkParts[1]
          || hkParts[0]
          || 'code';
        const mode =
          runContext?.workflowMeta?.default_mode
          || (String(runContext?.workflowKey || '').includes('build') ? 'build' : 'agent');

        // TIER_ORDER-based model selection: nano baseline, escalate by task complexity
        // gpt-5.4-nano: default workhorse (SQL, structured output, extraction, classification)
        // gpt-5.4-mini: code, multi-tool, CMS, terminal planning
        // gpt-5.4:      orchestration, final judge, approval summaries
        // Ollama:        local pin tests only (smoke=true paths)
        const TASK_TIER_MAP = {
          intent_classification: 'micro', rag_query: 'micro', summary: 'micro',
          skill_invocation: 'micro',      cms_theme_generation: 'micro',
          chat: 'standard',   code: 'standard',     cms_edit: 'standard',
          sql_d1_generation: 'standard',  terminal_execution: 'standard',
          plan: 'power', subagent_dispatch: 'power',
          workflow_orchestration: 'power', debug: 'power',
        };
        const desiredTierIdx = TIER_ORDER.indexOf(TASK_TIER_MAP[taskType] ?? 'standard');
        const resolvedCatalogKey = await (async () => {
          // Walk up tiers starting from desired until we find an active model
          for (const tier of TIER_ORDER.slice(desiredTierIdx >= 0 ? desiredTierIdx : 2)) {
            const row = await env.DB?.prepare(
              `SELECT model_key FROM agentsam_model_catalog
               WHERE tier = ? AND is_active = 1 AND supports_tools = 1
                 AND provider IN ('openai','anthropic','google')
               ORDER BY cost_per_1k_in ASC LIMIT 1`
            ).bind(tier).first().catch(() => null);
            if (row?.model_key) return row.model_key;
          }
          return 'gpt-5.4-nano'; // hard baseline — always available
        })();

        const userMsg = typeof input === 'string'
          ? input
          : input?.prompt || input?.message || input?.instruction || input?.result
          || JSON.stringify(input);

        const result = await dispatchComplete(env, {
          modelKey: resolvedCatalogKey,   // TIER_ORDER resolved: nano→mini→5.4 by task complexity
          taskType,
          mode,
          systemPrompt: 'You are Agent Sam, an autonomous AI developer for Inner Animal Media. Complete the task and return concise structured output.',
          messages: [{ role: 'user', content: String(userMsg).slice(0, 12000) }],
          userId: runContext?.canonicalUserId,
          options: { reasoningEffort: 'medium', verbosity: 'low' },
        });

        const text = result?.text
          || result?.content?.[0]?.text
          || result?.output
          || JSON.stringify(result);

        return { ok: true, output: { result: text, model: result?.model, tokens: result?.usage } };
      } catch (e) {
        return { ok: false, error: `agent node failed: ${e?.message ?? e}` };
      }
    }

    case 'mcp_tool': {
      if (smoke) {
        return {
          ok: true,
          output: {
            smoke: true,
            skipped: true,
            handler_key: handlerKey,
            note: 'mcp_tool smoke short-circuit',
          },
        };
      }
      const [, method] = (handlerKey || '').split('.');
      const toolKey = method || handlerKey;

      const toolRow = env.DB
        ? await env.DB.prepare(`
      SELECT tool_key, mcp_service_url, handler_type, handler_config
      FROM agentsam_mcp_tools
      WHERE tool_key = ? AND is_active = 1 AND enabled = 1
      LIMIT 1
    `)
            .bind(toolKey)
            .first()
            .catch(() => null)
        : null;

      if (!toolRow) {
        return { ok: false, error: `mcp_tool not found in agentsam_mcp_tools: ${handlerKey}` };
      }

      // Builtin/proxy/r2/terminal handlers — dispatch internally
      if (['builtin', 'r2', 'terminal', 'proxy'].includes(toolRow.handler_type)) {
        // These are handled by the existing tool dispatch system
        // Emit a tool call event and let the agent handler execute it
        return {
          ok: true,
          output: {
            tool_dispatched: toolRow.tool_key,
            handler_type: toolRow.handler_type,
            handler_config: JSON.parse(toolRow.handler_config || '{}'),
            input,
          },
        };
      }

      // HTTP/MCP server tools
      if (!toolRow.mcp_service_url) {
        return { ok: false, error: `no mcp_service_url for tool: ${handlerKey}` };
      }

      const mcpRes = await fetch(toolRow.mcp_service_url, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ method: toolRow.tool_key, params: input }),
      }).catch(() => null);

      if (!mcpRes?.ok) {
        return { ok: false, error: `mcp_tool HTTP ${mcpRes?.status}: ${handlerKey}` };
      }

      return { ok: true, output: await mcpRes.json().catch(() => ({})) };
    }

    case 'terminal': {
      if (smoke) {
        return {
          ok: true,
          output: { smoke: true, skipped: true, note: 'terminal smoke short-circuit' },
        };
      }
      const termUrl = env.TERMINAL_WS_URL
        ? env.TERMINAL_WS_URL.replace('wss://', 'https://').replace('ws://', 'http://')
        : null;
      if (!termUrl) return { ok: false, error: 'terminal not configured' };
      let nodeSchema = {};
      try { nodeSchema = JSON.parse(node?.input_schema_json || '{}'); } catch (_) {}
      // Also check if previous agent node embedded a command in its JSON result
      let _agentCmd = '';
      if (input?.result) {
        try {
          const _r = JSON.parse(input.result);
          _agentCmd = _r?.command || _r?.cmd || _r?.wrangler_command || '';
        } catch (_) {}
      }
      const cmd = input?.command || input?.cmd || _agentCmd || nodeSchema?.default_command || '';
      if (!cmd) return { ok: false, error: 'no command in terminal node input' };
      if (/[;&|`$><\\]/.test(cmd)) {
        return { ok: false, error: 'command contains unsafe characters' };
      }
      const tRes = await fetch(`${termUrl.replace(/\/$/, '')}/exec`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          Authorization: `Bearer ${env.TERMINAL_SECRET || ''}`,
        },
        body: JSON.stringify({ command: cmd, timeout_ms: node.timeout_ms || 30000 }),
      }).catch(() => null);
      if (!tRes?.ok) return { ok: false, error: `terminal HTTP ${tRes?.status}` };
      const out = await tRes.json().catch(() => ({}));
      return { ok: true, output: out };
    }

    case 'db_query': {
      return { ok: true, output: { logged: false, note: 'db_query noop — use dedicated analytics pipeline' } };
    }

    case 'eval': {
      let qg = {};
      try {
        qg = JSON.parse(node.quality_gate_json || '{}');
      } catch (_) {
        qg = {};
      }
      const assertions = qg.assertions || [];
      const passed = assertions.every((a) => {
        const val = input?.[a.field];
        if (a.op === 'exists') return val != null;
        if (a.op === 'eq') return val === a.value;
        if (a.op === 'gt') return Number(val) > Number(a.value);
        return true;
      });
      return { ok: true, output: { passed, assertion_count: assertions.length } };
    }

    case 'branch': {
      return { ok: true, output: { passed: true, branch: 'default' } };
    }

    case 'approval_gate': {
      if (smoke) {
        return {
          ok: true,
          output: { status: 'approved', smoke: true, skipped: true },
        };
      }
      if (!env.DB) return { ok: false, error: 'DB not available' };
      const approvalId = `appr_${crypto.randomUUID().replace(/-/g, '').slice(0, 16)}`;
      const meta = runContext?.runMeta || {};
      const payload = JSON.stringify({
        node_key: node.node_key,
        handler_key: handlerKey,
        input,
      });
      try {
        await env.DB.prepare(
          `INSERT INTO agentsam_approval_queue
           (id, tenant_id, workspace_id, user_id, workflow_run_id, tool_name, action_summary,
            input_json, risk_level, approval_type, status, created_at)
           VALUES (?,?,?,?,?,?,?,?,?,?, 'pending', unixepoch())`,
        ).bind(
          approvalId,
          meta.tenantId,
          meta.workspaceId,
          meta.userId,
          runContext.runId,
          `workflow:${String(node.node_key || 'gate').slice(0, 120)}`,
          `Workflow approval: ${node.node_key || 'gate'}`,
          payload,
          node.risk_level || 'high',
          'workflow',
        ).run();
      } catch (e) {
        return { ok: false, error: e?.message || 'approval_insert_failed' };
      }
      return { ok: true, output: { status: 'pending', approval_id: approvalId } };
    }

    case 'webhook': {
      if (smoke) return { ok: true, output: { smoke: true, skipped: true, note: 'webhook smoke short-circuit' } };
      const config = (() => {
        try { return JSON.parse(node.handler_config || node.config_json || '{}'); } catch { return {}; }
      })();
      const url = config.url || config.endpoint;
      if (!url) return { ok: false, error: `webhook node "${node.node_key}" missing url in handler_config` };
      const timeout = node.timeout_ms ?? 15_000;
      const ctrl = new AbortController();
      const timer = setTimeout(() => ctrl.abort(), timeout);
      try {
        const resp = await fetch(url, {
          method: config.method ?? 'POST',
          headers: { 'Content-Type': 'application/json', ...(config.headers ?? {}) },
          body: JSON.stringify({
            node_key: node.node_key,
            workflow_run_id: runContext?.runId,
            workflow_id: runContext?.workflowKey,
            ...input,
          }),
          signal: ctrl.signal,
        });
        clearTimeout(timer);
        if (!resp.ok) return { ok: false, error: `webhook HTTP ${resp.status} from ${url}` };
        const text = await resp.text();
        const output = (() => { try { return JSON.parse(text); } catch { return { raw: text }; } })();
        return { ok: true, output };
      } catch (e) {
        clearTimeout(timer);
        return { ok: false, error: `webhook fetch failed: ${e?.message ?? e}` };
      }
    }

    default:
      return { ok: false, error: `unknown node_type: ${nodeType}` };
  }
}

// ── Edge evaluation ──────────────────────────────────────────────────

function evaluateEdge(edge, nodeOutput) {
  let cond = {};
  try {
    cond = JSON.parse(edge.condition_json || '{}');
  } catch (_) {
    cond = {};
  }
  const ctype = String(edge.condition_type || 'always').toLowerCase();
  switch (ctype) {
    case 'always':
      return true;
    case 'status': {
      const expected = cond.from_status;
      const actual = nodeOutput?.ok ? 'success' : 'failed';
      if (Array.isArray(expected)) return expected.includes(actual);
      return actual === expected;
    }
    case 'risk': {
      if (cond.requires_approval) return nodeOutput?.output?.risk_level === 'high';
      if (cond.max_risk_level) {
        const lvl = TIER_ORDER.indexOf(nodeOutput?.output?.risk_level || 'low');
        const max = TIER_ORDER.indexOf(cond.max_risk_level);
        return lvl <= max;
      }
      return true;
    }
    case 'output': {
      const val = nodeOutput?.output?.[cond.field];
      return cond.op === 'eq' ? val === cond.value : val != null;
    }
    default:
      return false;
  }
}

function pickUsageFromNodeOutput(nodeOutput) {
  const o = nodeOutput?.output;
  if (!o || typeof o !== 'object') return { tin: 0, tout: 0, cost: 0 };
  const u = o.usage && typeof o.usage === 'object' ? o.usage : o;
  const tin = Number(u.input_tokens ?? u.prompt_tokens ?? o.tokens_in ?? 0) || 0;
  const tout = Number(u.output_tokens ?? u.completion_tokens ?? o.tokens_out ?? 0) || 0;
  const cost = Number(o.cost_usd ?? u.cost_usd ?? 0) || 0;
  return { tin, tout, cost };
}

function pickModelFromNodeOutput(nodeOutput) {
  const o = nodeOutput?.output;
  if (!o || typeof o !== 'object') return null;
  const u = o.usage && typeof o.usage === 'object' ? o.usage : o;
  const m = o.model_key ?? o.model ?? u.model_key ?? u.model ?? null;
  if (m == null || String(m).trim() === '') return null;
  return String(m).slice(0, 500);
}

const URL_IN_TEXT_RE = /https?:\/\/[^\s"'<>\])}]+/i;

function firstUrlFromWorkflowNodeInput(nodeInput) {
  if (!nodeInput || typeof nodeInput !== 'object') return undefined;
  const bc = nodeInput.browser_context ?? nodeInput.browserContext;
  if (bc && typeof bc === 'object') {
    const top = bc.url;
    if (typeof top === 'string' && /^https?:\/\//i.test(top.trim())) return top.trim().slice(0, 2000);
    const sel = bc.selected_element;
    if (sel && typeof sel === 'object') {
      const su = sel.url;
      if (typeof su === 'string' && /^https?:\/\//i.test(su.trim())) return su.trim().slice(0, 2000);
    }
  }
  for (const k of ['url', 'target_url', 'href', 'page_url', 'navigate_url']) {
    const u = nodeInput[k];
    if (typeof u === 'string' && /^https?:\/\//i.test(u.trim())) return u.trim().slice(0, 2000);
  }
  for (const k of ['message', 'prompt', 'instruction', 'result']) {
    const msg = nodeInput[k];
    if (typeof msg !== 'string') continue;
    const m = msg.match(URL_IN_TEXT_RE);
    if (m) return m[0].replace(/[.,;)\]]+$/, '').slice(0, 2000);
  }
  return undefined;
}

/** Map graph node → dashboard surface (SSE surface_open / App.tsx iam:agent-open-surface). */
function classifyWorkflowSurface(node) {
  if (!node || typeof node !== 'object') return null;
  const nk = String(node.node_key || '').toLowerCase();
  const hk = String(node.handler_key || '').toLowerCase();
  const nt = String(node.node_type || '').toLowerCase();

  if (hk.includes('monaco.') || hk.includes('.monaco.') || (hk.includes('monaco') && hk.includes('edit'))) {
    return { surface: 'code', reason: 'workflow_graph_monaco' };
  }
  if (nk.includes('monaco') || nk.includes('code_editor') || nk === 'editor' || nk.includes('app_builder')) {
    return { surface: 'code', reason: 'workflow_graph_code_surface' };
  }
  if (nk.includes('excalidraw') || hk.includes('excalidraw') || (nk.includes('diagram') && nk.includes('canvas'))) {
    return { surface: 'excalidraw', reason: 'workflow_graph_excalidraw' };
  }
  if (
    nk.includes('browser') ||
    nk.includes('playwright') ||
    nk.includes('screenshot') ||
    hk.includes('browser.') ||
    hk.includes('playwright') ||
    (nk.includes('navigate') && (nk.includes('url') || nk.includes('page')))
  ) {
    return { surface: 'browser', reason: 'workflow_graph_browser' };
  }
  if (nt === 'mcp_tool' && hk.startsWith('agentsam.code.') && (nk.includes('write') || nk.includes('apply') || nk.includes('patch'))) {
    return { surface: 'code', reason: 'workflow_graph_code_tool' };
  }
  return null;
}

/** Emit surface_open + agent_surface_open; returns proof for D1 output_json / workflow_step. */
function emitWorkflowGraphSurfaceEvents(onStream, { node, runId, workflowKey, nodeInput }) {
  if (typeof onStream !== 'function') return null;
  const spec = classifyWorkflowSurface(node);
  if (!spec) return null;
  const nodeKey = String(node?.node_key || '');
  const payload = {
    surface: spec.surface,
    reason: spec.reason,
    node_key: nodeKey,
    run_id: runId,
    workflow_key: workflowKey != null ? String(workflowKey) : undefined,
  };
  if (spec.surface === 'browser') {
    const url = firstUrlFromWorkflowNodeInput(nodeInput);
    if (url) payload.url = url;
  }
  try {
    onStream({ type: 'surface_open', ...payload });
    onStream({ type: 'agent_surface_open', ...payload });
  } catch (_) {
    /* stream closed */
  }
  return { ...payload, source: 'workflow_graph_node_start' };
}

function attachSurfaceProofToNodeOutput(nodeOutput, proof) {
  if (!proof) return nodeOutput;
  const base = nodeOutput && typeof nodeOutput === 'object' ? { ...nodeOutput } : { ok: !!nodeOutput?.ok };
  let out = base.output;
  if (out != null && typeof out === 'object' && !Array.isArray(out)) {
    out = { ...out, surface_open_proof: proof };
  } else if (out == null) {
    out = { surface_open_proof: proof };
  } else {
    out = { result: out, surface_open_proof: proof };
  }
  return { ...base, output: out };
}

/**
 * Canonical execution ledger row — agentsam_execution_steps.execution_id FK targets this id (not wrun_*).
 * Mirrors src/core/workflows.js flat runner.
 */
async function insertAgentsamExecutionForGraph(env, execCols, { tenantId, workspaceId, userId, runId, workflowKey }) {
  if (!env?.DB || !execCols?.size || !execCols.has('task_id')) return null;
  const workflowExecId = `exec_${crypto.randomUUID().replace(/-/g, '').slice(0, 16)}`;
  const wfKey = workflowKey != null ? String(workflowKey).slice(0, 500) : '';
  const uid =
    userId != null && String(userId).trim() !== ''
      ? await resolveCanonicalUserId(String(userId).trim(), env)
      : null;
  try {
    if (execCols.has('model_key')) {
      await env.DB.prepare(
        `INSERT OR IGNORE INTO agentsam_executions
         (id, tenant_id, workspace_id, user_id, command_run_id, task_id, execution_type, command,
          status, duration_ms, created_at)
         VALUES (?,?,?,?,?,?,?,?,?,?,unixepoch())`,
      )
        .bind(
          workflowExecId,
          tenantId ?? null,
          workspaceId,
          uid,
          null,
          runId,
          'workflow',
          wfKey || null,
          'running',
          0,
        )
        .run();
    } else {
      await env.DB.prepare(
        `INSERT OR IGNORE INTO agentsam_executions
         (id, tenant_id, workspace_id, user_id, task_id, execution_type, command, duration_ms, created_at)
         VALUES (?,?,?,?,?,?,?,?,unixepoch())`,
      )
        .bind(workflowExecId, tenantId ?? null, workspaceId, uid, runId, 'workflow', wfKey || null, 0)
        .run();
    }
    return workflowExecId;
  } catch (e) {
    console.warn('[workflow-graph] agentsam_executions insert failed', e?.message ?? e);
    return null;
  }
}

/** Pending step row — execution_id references agentsam_workflow_runs.id (runId). */
function ffPendingExecutionStep(db, cols, stepId, executionParentId, workflowRunId, node, inputPayload) {
  if (!db || !cols?.size) return;
  const hasExecCol = cols.has('execution_id');
  const hasWrunCol = cols.has('workflow_run_id');
  if (!hasExecCol && !hasWrunCol) return;
  if (hasExecCol && !executionParentId) return;

  const nk = String(node?.node_key ?? '').slice(0, 500);
  const nt = String(node?.node_type ?? '').slice(0, 120);
  const ij = JSON.stringify(inputPayload ?? {}).slice(0, 8000);

  const colNames = [];
  const placeholders = [];
  const binds = [];

  colNames.push('id');
  placeholders.push('?');
  binds.push(stepId);
  if (hasExecCol) {
    colNames.push('execution_id');
    placeholders.push('?');
    binds.push(executionParentId);
  }
  if (hasWrunCol) {
    colNames.push('workflow_run_id');
    placeholders.push('?');
    binds.push(workflowRunId);
  }
  colNames.push('node_key', 'node_type', 'status', 'input_json');
  placeholders.push('?', '?', '?', '?');
  binds.push(nk, nt, 'running', ij);
  if (cols.has('attempt')) {
    colNames.push('attempt');
    placeholders.push('?');
    binds.push(1);
  }
  if (cols.has('started_at')) {
    colNames.push('started_at');
    placeholders.push('?');
    binds.push(Math.floor(Date.now() / 1000));
  }
  colNames.push('created_at');
  placeholders.push(`datetime('now')`);

  const sql = `INSERT INTO agentsam_execution_steps (${colNames.join(', ')}) VALUES (${placeholders.join(', ')})`;
  void db
    .prepare(sql)
    .bind(...binds)
    .run()
    .catch((e) => console.warn('[workflow-graph] execution_steps insert', e?.message ?? e));
}

/** Fire-and-forget completion update — keyed by step id. */
function ffCompleteExecutionStep(db, cols, stepId, nodeStartMs, nodeOutput) {
  if (!db || !cols?.size || !stepId) return;
  const ok = !!nodeOutput?.ok;
  const latency = Math.max(0, Date.now() - nodeStartMs);
  const outJson = JSON.stringify(nodeOutput ?? {}).slice(0, 16000);
  const errObj = ok ? '{}' : JSON.stringify({ message: String(nodeOutput?.error ?? 'failed') }).slice(0, 8000);
  const { tin, tout, cost } = pickUsageFromNodeOutput(nodeOutput);
  const sets = [];
  const binds = [];
  sets.push('status = ?');
  binds.push(ok ? 'success' : 'failed');
  if (cols.has('output_json')) {
    sets.push('output_json = ?');
    binds.push(outJson);
  }
  if (cols.has('error_json')) {
    sets.push('error_json = ?');
    binds.push(errObj);
  }
  if (cols.has('completed_at')) sets.push('completed_at = unixepoch()');
  if (cols.has('latency_ms')) {
    sets.push('latency_ms = ?');
    binds.push(latency);
  }
  if (cols.has('tokens_in')) {
    sets.push('tokens_in = ?');
    binds.push(tin);
  }
  if (cols.has('tokens_out')) {
    sets.push('tokens_out = ?');
    binds.push(tout);
  }
  if (cols.has('cost_usd')) {
    sets.push('cost_usd = ?');
    binds.push(cost);
  }
  binds.push(stepId);
  const sql = `UPDATE agentsam_execution_steps SET ${sets.join(', ')} WHERE id = ?`;
  void db
    .prepare(sql)
    .bind(...binds)
    .run()
    .catch((e) => console.warn('[workflow-graph] execution_steps complete', e?.message ?? e));
}

function ffPatchExecutionStepEdge(db, cols, stepId, edge) {
  if (!db || !cols?.has?.('edge_taken') || !stepId || !edge) return;
  const label = String(edge.edge_key ?? edge.id ?? `${edge.from_node_key}->${edge.to_node_key}`).slice(0, 500);
  void db
    .prepare(`UPDATE agentsam_execution_steps SET edge_taken = ? WHERE id = ?`)
    .bind(label, stepId)
    .run()
    .catch((e) => console.warn('[workflow-graph] execution_steps edge_taken', e?.message ?? e));
}

// ── Main executor ────────────────────────────────────────────────────

export async function executeWorkflowGraph(env, opts) {
  const {
    workflowKey,
    input,
    tenantId,
    workspaceId,
    userId,
    userEmail,
    triggerType: triggerTypeRaw,
    toolBridge = null,
    onStep = null,
    onStream = null,
    onRunCreated = null,
  } = opts;

  if (!env.DB) return { ok: false, error: 'DB not available' };

  const triggerType = normalizeTriggerType(triggerTypeRaw);

  const workflow = await env.DB.prepare(
    `SELECT * FROM agentsam_workflows WHERE workflow_key = ? AND is_active = 1 LIMIT 1`,
  )
    .bind(workflowKey)
    .first();
  if (!workflow) return { ok: false, error: `workflow not found: ${workflowKey}` };

  const mcpRow = await resolveMcpWorkflowRow(env.DB, workflowKey, tenantId, workspaceId);
  const dagIds = [mcpRow?.id, workflow.id].filter(Boolean);
  const seen = new Set();
  const orderedDagIds = dagIds.filter((id) => {
    if (seen.has(id)) return false;
    seen.add(id);
    return true;
  });

  let nodes = [];
  let edges = [];
  let dagWorkflowId = null;
  for (const wid of orderedDagIds) {
    const nRes = await env.DB.prepare(
      `SELECT * FROM agentsam_workflow_nodes
       WHERE workflow_id = ? AND COALESCE(is_active, 1) = 1 ORDER BY sort_order ASC`,
    )
      .bind(wid)
      .all();
    const eRes = await env.DB.prepare(
      `SELECT * FROM agentsam_workflow_edges WHERE workflow_id = ? ORDER BY priority ASC`,
    )
      .bind(wid)
      .all();
    const nl = nRes?.results || [];
    if (nl.length) {
      nodes = nl;
      edges = eRes?.results || [];
      dagWorkflowId = wid;
      break;
    }
  }

  if (!nodes?.length) return { ok: false, error: 'no nodes found for workflow' };

  const runWorkflowId = mcpRow?.id ?? dagWorkflowId ?? workflow.id;

  const runId = `wrun_${crypto.randomUUID().replace(/-/g, '').slice(0, 16)}`;
  const firstKey = nodes[0]?.node_key || '';
  await env.DB.prepare(
    `INSERT INTO agentsam_workflow_runs (
      id, workflow_id, workflow_key, tenant_id, workspace_id,
      user_id, user_email, trigger_type, status,
      input_json, output_json, step_results_json, metadata_json,
      steps_total, steps_completed, environment,
      graph_mode, current_node_key,
      started_at, created_at, updated_at
    ) VALUES (
      ?, ?, ?, ?, ?,
      ?, ?, ?, 'running',
      ?, '{}', '[]', '{}',
      ?, 0, 'production',
      1, ?,
      unixepoch(), datetime('now'), datetime('now')
    )`,
  )
    .bind(
      runId,
      runWorkflowId,
      workflowKey,
      tenantId,
      workspaceId,
      userId ?? null,
      userEmail ?? null,
      triggerType,
      JSON.stringify(input ?? {}),
      nodes.length,
      firstKey,
    )
    .run();

  const runStartedAt = Date.now();
  try {
    onRunCreated?.(runId, { steps_total: nodes.length });
  } catch (_) {
    /* non-fatal */
  }

  const canonicalUserId = await resolveCanonicalUserId(userId, env);
  const stepCols = await pragmaTableInfo(env.DB, 'agentsam_execution_steps');
  const execCols = await pragmaTableInfo(env.DB, 'agentsam_executions');
  const workflowExecId = await insertAgentsamExecutionForGraph(env, execCols, {
    tenantId,
    workspaceId,
    userId,
    runId,
    workflowKey,
  });

  const nodeMap = Object.fromEntries(nodes.map((n) => [n.node_key, n]));
  const edgeMap = {};
  for (const e of edges || []) {
    if (!edgeMap[e.from_node_key]) edgeMap[e.from_node_key] = [];
    edgeMap[e.from_node_key].push(e);
  }

  const runMeta = { tenantId, workspaceId, userId: canonicalUserId };

  // Fetch workflow row once so every dispatchNode call can read default_task_type / default_mode
  // This is what makes agentsam_workflows drive TIER_ORDER model selection correctly
  const workflowMeta = env.DB
    ? await env.DB
        .prepare(
          `SELECT default_task_type, default_mode, workflow_type, risk_level, requires_approval
           FROM agentsam_workflows
           WHERE (id = ? OR workflow_key = ?) AND COALESCE(is_active, 1) = 1
           LIMIT 1`
        )
        .bind(workflowKey, workflowKey)
        .first()
        .catch(() => null)
    : null;

  const runContext = {
    runId,
    runMeta,
    workflowRunId: runId,
    canonicalUserId,
    workflowExecId,
    toolBridge,
    workflowKey,
    workflowMeta: workflowMeta ?? null,
  };
  const streamSse =
    typeof onStream === 'function'
      ? onStream
      : toolBridge && typeof toolBridge.emitSse === 'function'
        ? toolBridge.emitSse
        : null;
  const stepResults = [];
  let currentNodeKey = firstKey;
  let stepsCompleted = 0;
  let totalCostUsd = 0;
  let totalInputTokens = 0;
  let totalOutputTokens = 0;
  let lastModelUsed = null;
  let runOk = true;
  let killReason = null;
  let previousStepId = null;

  // 5. Walk the graph
  const visited = new Set();
  while (currentNodeKey) {
    if (visited.has(currentNodeKey)) {
      killReason = 'cycle_detected';
      runOk = false;
      break;
    }
    if (stepsCompleted > nodes.length + 5) {
      killReason = 'max_steps_exceeded';
      runOk = false;
      break;
    }
    visited.add(currentNodeKey);

    const node = nodeMap[currentNodeKey];
    if (!node) {
      killReason = `node_not_found:${currentNodeKey}`;
      runOk = false;
      break;
    }

    await env.DB
      .prepare(
        `UPDATE agentsam_workflow_runs SET
        current_node_key = ?,
        heartbeat_at     = unixepoch(),
        updated_at       = datetime('now')
      WHERE id = ?`,
      )
      .bind(currentNodeKey, runId)
      .run()
      .catch(() => null);

    const nodeInput =
      stepResults.length > 0 ? stepResults[stepResults.length - 1].output ?? input : input;

    const stepId = `estep_${crypto.randomUUID().replace(/-/g, '').slice(0, 16)}`;
    const nodeStartTime = Date.now();
    ffPendingExecutionStep(env.DB, stepCols, stepId, runId, runId, node, nodeInput);

    if (false && tenantId && previousStepId && workspaceId) {
      // dep_graph FKs to agentsam_tool_chain — not estep IDs. Disabled.
      void insertExecutionDependencyGraphEdge(env, tenantId, stepId, previousStepId, workspaceId).catch(
        () => {},
      );
    }

    const surfaceProof = emitWorkflowGraphSurfaceEvents(streamSse, {
      node,
      runId,
      workflowKey,
      nodeInput,
    });

    let nodeOutput = await dispatchNode(env, node, nodeInput, {
      ...runContext,
      node,
      executionStepId: stepId,
    }).catch((e) => ({
      ok: false,
      error: e?.message || String(e),
    }));

    nodeOutput = attachSurfaceProofToNodeOutput(nodeOutput, surfaceProof);

    ffCompleteExecutionStep(env.DB, stepCols, stepId, nodeStartTime, nodeOutput);

    const usage = pickUsageFromNodeOutput(nodeOutput);
    totalInputTokens += usage.tin;
    totalOutputTokens += usage.tout;
    totalCostUsd += usage.cost;
    const stepModel = pickModelFromNodeOutput(nodeOutput);
    if (stepModel) lastModelUsed = stepModel;

    previousStepId = stepId;

    stepResults.push({
      node_key: currentNodeKey,
      node_type: node.node_type,
      handler_key: node.handler_key,
      ok: nodeOutput.ok,
      output: nodeOutput.output ?? null,
      error: nodeOutput.error ?? null,
    });
    stepsCompleted += 1;

    await env.DB
      .prepare(
        `UPDATE agentsam_workflow_runs SET
        steps_completed   = ?,
        step_results_json = ?,
        updated_at        = datetime('now')
      WHERE id = ?`,
      )
      .bind(stepsCompleted, JSON.stringify(stepResults), runId)
      .run()
      .catch(() => null);

    try {
      onStep?.({
        run_id: runId,
        workflow_key: workflowKey,
        node_key: currentNodeKey,
        current_node_key: currentNodeKey,
        steps_completed: stepsCompleted,
        steps_total: nodes.length,
        input_tokens: totalInputTokens,
        output_tokens: totalOutputTokens,
        cost_usd: totalCostUsd,
        ok: nodeOutput.ok,
        surface_open_proof: surfaceProof || undefined,
      });
    } catch (_) {
      /* ignore stream errors */
    }

    if (!nodeOutput.ok) {
      runOk = false;
      killReason = nodeOutput.error || 'node_failed';
      break;
    }

    if (node.node_type === 'approval_gate' && nodeOutput.output?.status === 'pending') {
      await env.DB
        .prepare(
          `UPDATE agentsam_workflow_runs SET
          status         = 'awaiting_approval',
          input_tokens   = ?,
          output_tokens  = ?,
          cost_usd       = ?,
          model_used     = ?,
          updated_at     = datetime('now')
        WHERE id = ?`,
        )
        .bind(totalInputTokens, totalOutputTokens, totalCostUsd, lastModelUsed, runId)
        .run()
        .catch(() => null);
      return {
        ok: true,
        status: 'awaiting_approval',
        run_id: runId,
        approval_id: nodeOutput.output.approval_id,
        step_results: stepResults,
      };
    }

    const outEdges = (edgeMap[currentNodeKey] || []).sort((a, b) => {
      if (a.is_fallback !== b.is_fallback) return a.is_fallback ? 1 : -1;
      return (a.priority || 0) - (b.priority || 0);
    });

    let nextNodeKey = null;
    let chosenEdge = null;
    for (const edge of outEdges) {
      if (evaluateEdge(edge, nodeOutput)) {
        nextNodeKey = edge.to_node_key;
        chosenEdge = edge;
        break;
      }
    }

    ffPatchExecutionStepEdge(env.DB, stepCols, stepId, chosenEdge);

    currentNodeKey = nextNodeKey;
  }

  // 6. Finalize run row
  const finalStatus = runOk ? 'completed' : 'failed';
  const lastOutput = stepResults[stepResults.length - 1]?.output ?? {};
  const runDurationMs = Math.max(0, Date.now() - runStartedAt);

  const killClause = killReason ? 'kill_reason = ?,' : '';
  const killBinds = killReason ? [killReason] : [];
  const errClause = !runOk && killReason ? 'error_message = ?,' : '';
  const errBinds = !runOk && killReason ? [String(killReason).slice(0, 4000)] : [];

  await env.DB
    .prepare(
      `UPDATE agentsam_workflow_runs SET
      status            = ?,
      output_json       = ?,
      step_results_json = ?,
      steps_completed   = ?,
      input_tokens      = ?,
      output_tokens     = ?,
      cost_usd          = ?,
      model_used        = ?,
      duration_ms       = ?,
      completed_at      = unixepoch(),
      ${killClause}
      ${errClause}
      updated_at        = datetime('now')
    WHERE id = ?`,
    )
    .bind(
      finalStatus,
      JSON.stringify(lastOutput),
      JSON.stringify(stepResults),
      stepsCompleted,
      totalInputTokens,
      totalOutputTokens,
      totalCostUsd,
      lastModelUsed,
      runDurationMs,
      ...killBinds,
      ...errBinds,
      runId,
    )
    .run()
    .catch(() => null);

  return {
    ok: runOk,
    status: finalStatus,
    run_id: runId,
    steps_completed: stepsCompleted,
    step_results: stepResults,
    kill_reason: killReason ?? null,
  };
}

// ── SSE streaming wrapper ────────────────────────────────────────────

export async function executeWorkflowAndStream(
  env,
  workflowKey,
  inputOrMessage,
  authUser,
  workspaceId,
  controller,
  streamOpts = {},
) {
  const encoder = new TextEncoder();
  const send = (data) => {
    try {
      controller.enqueue(encoder.encode(`data: ${JSON.stringify(data)}\n\n`));
    } catch {
      /* stream already closed */
    }
  };

  const input =
    typeof inputOrMessage === 'string'
      ? { message: inputOrMessage }
      : inputOrMessage && typeof inputOrMessage === 'object'
        ? inputOrMessage
        : { message: String(inputOrMessage || '') };

  const { toolBridge: streamToolBridge } = streamOpts;
  const mergedBridge =
    streamToolBridge && typeof streamToolBridge === 'object'
      ? { ...streamToolBridge, emitSse: send }
      : { emitSse: send };

  const result = await executeWorkflowGraph(env, {
    workflowKey,
    input,
    tenantId: authUser?.tenant_id ?? null,
    workspaceId,
    userId: authUser?.id ?? null,
    userEmail: authUser?.email ?? null,
    toolBridge: mergedBridge,
    onRunCreated: (runId, meta) =>
      send({
        type: 'workflow_start',
        workflow_key: workflowKey,
        run_id: runId,
        steps_total: meta?.steps_total ?? null,
      }),
    onStep: (evt) => send({ type: 'workflow_step', ...evt }),
  }).catch((e) => ({
    ok: false,
    status: 'error',
    run_id: null,
    step_results: [],
    kill_reason: e?.message || String(e),
  }));

  if (result.status === 'awaiting_approval') {
    send({
      type: 'workflow_approval_required',
      run_id: result.run_id,
      approval_id: result.approval_id,
      message:
        'This workflow requires approval before continuing. Use /api/agent/workflow/approve to proceed.',
    });
  } else {
    send({
      type: result.ok ? 'workflow_complete' : 'workflow_error',
      status: result.status,
      run_id: result.run_id,
      message: result.ok
        ? `Workflow ${workflowKey} completed (${result.steps_completed} steps).`
        : `Workflow failed: ${result.kill_reason || 'unknown error'}`,
    });
  }

  send({ type: 'done' });
  try {
    controller.close();
  } catch {
    /* noop */
  }
}

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { Sparkles, Send, Trash2, Zap, CheckCircle2, XCircle, Loader2 } from 'lucide-react';
import { DataGrid } from './DataGrid';
import type { SqlDialect } from './SQLConsole';

export type SqlRunResult = {
  success: boolean;
  results?: Record<string, unknown>[];
  error?: string;
  meta?: unknown;
};

type ChatMsg = {
  id: string;
  role: 'user' | 'assistant' | 'system';
  sql?: string;
  text?: string;
  error?: string;
  results?: Record<string, unknown>[];
  meta?: unknown;
};

const SUGGESTIONS: Record<SqlDialect, { label: string; sql: string }[]> = {
  d1: [
    { label: 'List tables', sql: `SELECT name FROM sqlite_master WHERE type='table' ORDER BY name;` },
    { label: 'SQLite version', sql: `SELECT sqlite_version() AS version;` },
    { label: 'Count tables', sql: `SELECT COUNT(*) AS table_count FROM sqlite_master WHERE type='table';` },
  ],
  postgres: [
    {
      label: 'Public tables',
      sql: `SELECT table_schema, table_name, table_type
FROM information_schema.tables
WHERE table_schema NOT IN ('pg_catalog','information_schema')
ORDER BY table_schema, table_name
LIMIT 50;`,
    },
    { label: 'Extensions', sql: `SELECT extname, extversion FROM pg_extension ORDER BY 1;` },
    { label: 'pgvector check', sql: `SELECT EXISTS (SELECT 1 FROM pg_extension WHERE extname = 'vector') AS pgvector_installed;` },
  ],
};

function id(): string {
  return `m_${Date.now()}_${Math.random().toString(36).slice(2, 9)}`;
}

interface DatabaseAgentChatProps {
  runSQL: (sql: string) => Promise<SqlRunResult>;
  dialect: SqlDialect;
  dbLabel: string;
}

export const DatabaseAgentChat: React.FC<DatabaseAgentChatProps> = ({ runSQL, dialect, dbLabel }) => {
  const [input, setInput] = useState('');
  const [messages, setMessages] = useState<ChatMsg[]>([
    {
      id: id(),
      role: 'system',
      text: `Database agent for ${dbLabel}. Paste SQL and press Run. Suggestions below match your current engine (${dialect === 'postgres' ? 'PostgreSQL / Hyperdrive' : 'SQLite / D1'}).`,
    },
  ]);
  const [running, setRunning] = useState(false);
  const bottomRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, running]);

  const executeSql = useCallback(
    async (sql: string) => {
      const trimmed = sql.trim();
      if (!trimmed) return;
      const userMsg: ChatMsg = { id: id(), role: 'user', sql: trimmed };
      setMessages((prev) => [...prev, userMsg]);
      setRunning(true);
      try {
        const out = await runSQL(trimmed);
        if (out.success) {
          const rows = out.results ?? [];
          const meta = out.meta;
          setMessages((prev) => [
            ...prev,
            {
              id: id(),
              role: 'assistant',
              results: rows,
              meta,
              text:
                rows.length === 0 && meta != null
                  ? 'Statement completed.'
                  : rows.length === 0
                    ? 'OK (no rows returned).'
                    : undefined,
            },
          ]);
        } else {
          setMessages((prev) => [
            ...prev,
            {
              id: id(),
              role: 'assistant',
              error: out.error || 'Query failed',
            },
          ]);
        }
      } catch (e) {
        setMessages((prev) => [
          ...prev,
          {
            id: id(),
            role: 'assistant',
            error: e instanceof Error ? e.message : String(e),
          },
        ]);
      } finally {
        setRunning(false);
      }
    },
    [runSQL],
  );

  const runFromInput = () => {
    const sql = input.trim();
    if (!sql || running) return;
    setInput('');
    void executeSql(sql);
  };

  const onSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    runFromInput();
  };

  const clearChat = () => {
    setMessages([
      {
        id: id(),
        role: 'system',
        text: 'Chat cleared. Paste SQL to run against the active connection.',
      },
    ]);
  };

  return (
    <div className="flex flex-col h-full bg-[var(--bg-app)] overflow-hidden">
      <div className="px-4 py-2 border-b border-[var(--border-subtle)] flex items-center justify-between bg-[var(--bg-panel)] shrink-0">
        <div className="flex items-center gap-2">
          <div className="p-1.5 rounded-lg bg-[var(--solar-magenta)]/15">
            <Sparkles size={14} className="text-[var(--solar-magenta)]" />
          </div>
          <div>
            <div className="text-[11px] font-bold uppercase tracking-widest">Database agent</div>
            <div className="text-[9px] text-[var(--text-muted)] font-mono">{dbLabel}</div>
          </div>
        </div>
        <button
          type="button"
          onClick={clearChat}
          className="flex items-center gap-1 px-2 py-1 rounded text-[10px] font-bold uppercase tracking-widest text-[var(--text-muted)] hover:bg-[var(--bg-hover)] hover:text-[var(--text-main)]"
        >
          <Trash2 size={11} /> Clear
        </button>
      </div>

      <div className="flex-1 overflow-y-auto p-4 space-y-4 custom-scrollbar">
        {messages.map((m) => (
          <div
            key={m.id}
            className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}
          >
            <div
              className={`max-w-[min(100%,42rem)] rounded-xl border px-3 py-2.5 text-[12px] ${
                m.role === 'user'
                  ? 'bg-[var(--solar-cyan)]/10 border-[var(--solar-cyan)]/25 text-[var(--text-main)]'
                  : m.role === 'system'
                    ? 'bg-[var(--bg-panel)] border-[var(--border-subtle)] text-[var(--text-muted)] italic'
                    : m.error
                      ? 'bg-[var(--solar-red)]/8 border-[var(--solar-red)]/25 text-[var(--text-main)]'
                      : 'bg-[var(--bg-panel)] border-[var(--border-subtle)] text-[var(--text-main)]'
              }`}
            >
              {m.role === 'user' && m.sql && (
                <pre className="text-[11px] font-mono whitespace-pre-wrap break-words text-[var(--solar-cyan)]">{m.sql}</pre>
              )}
              {m.role === 'system' && m.text && <p className="text-[11px] leading-relaxed not-italic">{m.text}</p>}
              {m.role === 'assistant' && m.error && (
                <div className="flex items-start gap-2">
                  <XCircle size={14} className="text-[var(--solar-red)] shrink-0 mt-0.5" />
                  <div>
                    <div className="text-[10px] font-black uppercase tracking-widest text-[var(--solar-red)] mb-1">Error</div>
                    <pre className="text-[11px] font-mono whitespace-pre-wrap break-words">{m.error}</pre>
                  </div>
                </div>
              )}
              {m.role === 'assistant' && !m.error && (
                <div className="space-y-2">
                  <div className="flex items-center gap-2 text-[10px] font-black uppercase tracking-widest text-[var(--solar-green)]">
                    <CheckCircle2 size={12} />
                    Success
                    {m.results != null && (
                      <span className="font-mono font-normal text-[var(--text-muted)] normal-case">
                        {m.results.length} row{m.results.length === 1 ? '' : 's'}
                      </span>
                    )}
                  </div>
                  {m.text && <p className="text-[11px] text-[var(--text-muted)]">{m.text}</p>}
                  {m.meta != null && (
                    <pre className="text-[10px] font-mono p-2 rounded bg-[var(--bg-app)] border border-[var(--border-subtle)] overflow-x-auto text-[var(--text-muted)]">
                      {JSON.stringify(m.meta, null, 2)}
                    </pre>
                  )}
                  {m.results && m.results.length > 0 && (
                    <div className="max-h-[min(60vh,28rem)] overflow-auto rounded-lg border border-[var(--border-subtle)]">
                      <DataGrid data={m.results} />
                    </div>
                  )}
                </div>
              )}
            </div>
          </div>
        ))}
        {running && (
          <div className="flex justify-start">
            <div className="flex items-center gap-2 px-3 py-2 rounded-xl border border-[var(--border-subtle)] bg-[var(--bg-panel)] text-[11px] text-[var(--text-muted)]">
              <Loader2 size={14} className="animate-spin text-[var(--solar-cyan)]" />
              Running query…
            </div>
          </div>
        )}
        <div ref={bottomRef} />
      </div>

      <div className="border-t border-[var(--border-subtle)] bg-[var(--bg-panel)] p-3 shrink-0">
        <div className="flex flex-wrap gap-1.5 mb-2">
          {SUGGESTIONS[dialect].map((s) => (
            <button
              key={s.label}
              type="button"
              disabled={running}
              onClick={() => void executeSql(s.sql)}
              className="inline-flex items-center gap-1 px-2 py-1 rounded-md text-[10px] font-bold uppercase tracking-widest bg-[var(--bg-app)] border border-[var(--border-subtle)] text-[var(--text-muted)] hover:border-[var(--solar-cyan)]/40 hover:text-[var(--text-main)] disabled:opacity-50"
            >
              <Zap size={10} className="text-[var(--solar-orange)]" />
              {s.label}
            </button>
          ))}
        </div>
        <form onSubmit={onSubmit} className="flex gap-2">
          <textarea
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => {
              if (e.key === 'Enter' && !e.shiftKey) {
                e.preventDefault();
                runFromInput();
              }
            }}
            placeholder="Write SQL… (Enter to run, Shift+Enter for newline)"
            rows={3}
            disabled={running}
            spellCheck={false}
            className="flex-1 resize-none rounded-lg border border-[var(--border-subtle)] bg-[var(--bg-app)] px-3 py-2 text-[12px] font-mono text-[var(--text-main)] placeholder:text-[var(--text-muted)] focus:outline-none focus:border-[var(--solar-cyan)]/50 disabled:opacity-50"
          />
          <button
            type="submit"
            disabled={running || !input.trim()}
            className="self-end px-4 py-2 rounded-lg bg-[var(--solar-cyan)]/20 border border-[var(--solar-cyan)]/35 text-[var(--solar-cyan)] text-[11px] font-bold uppercase tracking-widest hover:bg-[var(--solar-cyan)]/30 disabled:opacity-40 flex items-center gap-2 shrink-0"
          >
            {running ? <Loader2 size={14} className="animate-spin" /> : <Send size={14} />}
            Run
          </button>
        </form>
      </div>
    </div>
  );
};

import React, { useCallback, useEffect, useMemo, useState } from 'react';
import type { AnalyticsLayoutResponse } from '../types';
import { AgentChatPlanTracePanel } from '../panels/AgentChatPlanTracePanel';

type Props = { layout: AnalyticsLayoutResponse | null };

type Range = '24h' | '7d' | '30d' | 'all';

async function getJson<T>(url: string): Promise<T | null> {
  try {
    const res = await fetch(url, { credentials: 'include' });
    if (!res.ok) return null;
    return (await res.json()) as T;
  } catch {
    return null;
  }
}

function Section({
  title,
  subtitle,
  children,
}: {
  title: string;
  subtitle?: string;
  children: React.ReactNode;
}) {
  return (
    <section className="rounded-lg border border-slate-800/90 bg-slate-950/45 overflow-hidden">
      <header className="border-b border-slate-800/80 px-3 py-2 bg-slate-950/60">
        <h3 className="text-[13px] font-semibold text-slate-100">{title}</h3>
        {subtitle ? <p className="text-[11px] text-slate-500 mt-0.5">{subtitle}</p> : null}
      </header>
      <div className="p-3 text-[12px] text-slate-300">{children}</div>
    </section>
  );
}

function fmtTs(v: unknown): string {
  if (v == null) return '—';
  const n = Number(v);
  if (Number.isFinite(n) && n > 1e9) {
    try {
      return new Date(n * 1000).toISOString().replace('T', ' ').slice(0, 19);
    } catch {
      return String(v);
    }
  }
  return String(v);
}

export default function AgentTab(_props: Props) {
  const [range, setRange] = useState<Range>('7d');
  const [runs, setRuns] = useState<Record<string, unknown>[] | null>(null);
  const [runSummary, setRunSummary] = useState<Record<string, unknown> | null>(null);
  const [selectedRunId, setSelectedRunId] = useState<string | null>(null);
  const [detail, setDetail] = useState<Record<string, unknown> | null>(null);
  const [graph, setGraph] = useState<Record<string, unknown> | null>(null);
  const [deps, setDeps] = useState<Record<string, unknown> | null>(null);
  const [inspector, setInspector] = useState<Record<string, unknown> | null>(null);
  const [err, setErr] = useState<string | null>(null);

  const loadList = useCallback(async () => {
    setErr(null);
    const j = await getJson<{
      rows?: Record<string, unknown>[];
      summary?: Record<string, unknown>;
      warnings?: { message?: string }[];
    }>(`/api/analytics/agent/runs?range=${range}&limit=50`);
    if (!j) {
      setErr('Failed to load workflow runs');
      setRuns([]);
      return;
    }
    const nextRows = j.rows || [];
    setRuns(nextRows);
    setRunSummary(j.summary || {});
    setSelectedRunId((prev) => {
      if (prev && nextRows.some((r) => String(r.id) === prev)) return prev;
      return nextRows[0]?.id ? String(nextRows[0].id) : null;
    });
  }, [range]);

  useEffect(() => {
    void loadList();
  }, [loadList]);

  useEffect(() => {
    let alive = true;
    (async () => {
      if (!selectedRunId) {
        setDetail(null);
        return;
      }
      const d = await getJson<Record<string, unknown>>(
        `/api/analytics/agent/runs?range=${range}&run_id=${encodeURIComponent(selectedRunId)}`,
      );
      if (!alive) return;
      setDetail(d);
    })();
    return () => {
      alive = false;
    };
  }, [selectedRunId, range]);

  useEffect(() => {
    let alive = true;
    (async () => {
      const [g, dp] = await Promise.all([
        getJson<Record<string, unknown>>(`/api/analytics/agent/graph?range=${range}`),
        getJson<Record<string, unknown>>(`/api/analytics/agent/dependencies?range=${range}`),
      ]);
      if (!alive) return;
      setGraph(g);
      setDeps(dp);
    })();
    return () => {
      alive = false;
    };
  }, [range]);

  const wf = graph?.summary as Record<string, unknown> | undefined;
  const nodes = (wf?.nodes as Record<string, unknown>[]) || [];
  const edges = (wf?.edges as Record<string, unknown>[]) || [];
  const depRows = (deps?.rows as Record<string, unknown>[]) || [];

  const waterfall = (detail?.waterfall as Record<string, unknown>[]) || [];
  const failurePath = (detail?.failurePath as Record<string, unknown>[]) || [];
  const toolLedger = (detail?.toolLedger as Record<string, unknown>[]) || [];
  const runRow = (detail?.summary as { run?: Record<string, unknown> } | undefined)?.run;

  const statusChips = useMemo(() => {
    const by = (runSummary?.by_status || {}) as Record<string, number>;
    return Object.entries(by).sort((a, b) => b[1] - a[1]);
  }, [runSummary]);

  return (
    <div className="flex flex-col gap-3">
      <div className="flex flex-wrap items-center justify-between gap-2">
        <div>
          <div className="text-sm font-semibold text-slate-100">Agent Sam · execution spine</div>
          <div className="text-[11px] text-slate-500">
            D1 workflow runs, execution steps, workflow DAG, dependency edges, and tool ledger — not chart-first.
          </div>
        </div>
        <div className="flex items-center gap-2">
          <label className="text-[11px] text-slate-500">Range</label>
          <select
            className="rounded border border-slate-700 bg-slate-950 px-2 py-1 text-[12px] text-slate-200"
            value={range}
            onChange={(e) => setRange(e.target.value as Range)}
          >
            <option value="24h">24h</option>
            <option value="7d">7d</option>
            <option value="30d">30d</option>
            <option value="all">All</option>
          </select>
          <button
            type="button"
            className="rounded border border-slate-600 px-2 py-1 text-[12px] text-slate-200 hover:bg-slate-800/80"
            onClick={() => void loadList()}
          >
            Refresh
          </button>
        </div>
      </div>

      {err ? (
        <div className="rounded border border-rose-900/50 bg-rose-950/30 p-2 text-[12px] text-rose-100">{err}</div>
      ) : null}

      <AgentChatPlanTracePanel />

      <div className="grid gap-3 xl:grid-cols-12">
        <div className="xl:col-span-4 space-y-3">
          <Section title="Run timeline" subtitle="agentsam_workflow_runs — newest first">
            {statusChips.length ? (
              <div className="mb-2 flex flex-wrap gap-1">
                {statusChips.map(([k, v]) => (
                  <span
                    key={k}
                    className="rounded bg-slate-900/80 px-1.5 py-0.5 font-mono text-[10px] text-slate-400"
                  >
                    {k}:{v}
                  </span>
                ))}
              </div>
            ) : null}
            <div className="max-h-[420px] overflow-auto space-y-1">
              {(runs || []).map((r) => {
                const id = String(r.id || '');
                const active = id === selectedRunId;
                return (
                  <button
                    key={id || Math.random()}
                    type="button"
                    onClick={() => setSelectedRunId(id)}
                    className={`flex w-full flex-col rounded border px-2 py-1.5 text-left font-mono text-[11px] ${
                      active
                        ? 'border-cyan-700/60 bg-cyan-950/25 text-cyan-100'
                        : 'border-slate-800 bg-slate-950/30 text-slate-300 hover:border-slate-600'
                    }`}
                  >
                    <div className="flex justify-between gap-2">
                      <span className="truncate">{id}</span>
                      <span className="shrink-0 text-slate-500">{String(r.status || '')}</span>
                    </div>
                    <div className="mt-0.5 flex justify-between gap-2 text-[10px] text-slate-500">
                      <span className="truncate">{String(r.workflow_key || r.workflow_id || '')}</span>
                      <span>{fmtTs(r.started_at)}</span>
                    </div>
                  </button>
                );
              })}
              {runs && runs.length === 0 ? <div className="text-slate-500">No runs in window.</div> : null}
            </div>
          </Section>
        </div>

        <div className="xl:col-span-8 space-y-3">
          <Section title="Pinned run" subtitle="agentsam_execution_steps · step_results_json waterfall">
            {!runRow ? (
              <div className="text-slate-500">Select a run from the timeline.</div>
            ) : (
              <div className="space-y-2">
                <div className="flex flex-wrap gap-3 font-mono text-[11px] text-slate-400">
                  <span>
                    <span className="text-slate-600">status</span> {String(runRow.status)}
                  </span>
                  <span>
                    <span className="text-slate-600">model</span> {String(runRow.model_used || '—')}
                  </span>
                  <span>
                    <span className="text-slate-600">duration_ms</span> {String(runRow.duration_ms ?? '—')}
                  </span>
                  <span>
                    <span className="text-slate-600">tokens</span>{' '}
                    {Number(runRow.input_tokens || 0) + Number(runRow.output_tokens || 0)}
                  </span>
                  <span>
                    <span className="text-slate-600">supabase_sync</span>{' '}
                    {String(runRow.supabase_sync_status || '—')}
                  </span>
                </div>
                {failurePath.length ? (
                  <div className="rounded border border-rose-900/40 bg-rose-950/20 p-2">
                    <div className="text-[11px] font-semibold text-rose-100">Failure path</div>
                    <ul className="mt-1 list-inside list-disc text-[11px] text-rose-200/90">
                      {failurePath.map((f) => (
                        <li key={String(f.id)}>
                          {String(f.node_key || '—')} · {String(f.status)}{' '}
                          <span className="text-rose-300/80">
                            {String(f.error_json_preview || '').slice(0, 120)}
                          </span>
                        </li>
                      ))}
                    </ul>
                  </div>
                ) : null}
                <div className="space-y-1">
                  <div className="text-[11px] text-slate-500">Step waterfall (latency bar)</div>
                  {waterfall.length ? (
                    waterfall.map((w, i) => {
                      const bar = Math.round((Number(w.bar) || 0) * 100);
                      const ok = String(w.status || '').toLowerCase().includes('fail') ? false : true;
                      return (
                        <div key={`${String(w.node_key)}-${i}`} className="flex items-center gap-2">
                          <div className="w-36 shrink-0 truncate font-mono text-[10px] text-slate-400" title={String(w.node_key)}>
                            {String(w.node_key || '—')}
                          </div>
                          <div className="flex-1 h-2 rounded bg-slate-900">
                            <div
                              className={`h-2 rounded ${ok ? 'bg-cyan-700/70' : 'bg-rose-600/80'}`}
                              style={{ width: `${bar}%` }}
                            />
                          </div>
                          <div className="w-16 shrink-0 text-right font-mono text-[10px] text-slate-500">
                            {Number(w.latency_ms || 0)}ms
                          </div>
                        </div>
                      );
                    })
                  ) : (
                    <div className="text-slate-500">No waterfall rows (no steps / empty step_results_json).</div>
                  )}
                </div>
              </div>
            )}
          </Section>

          <div className="grid gap-3 lg:grid-cols-2">
            <Section title="Workflow DAG" subtitle="agentsam_workflow_nodes + agentsam_workflow_edges">
              {String(wf?.state || '') !== 'LIVE' ? (
                <div className="text-slate-500">No graph in scope ({String(wf?.state || 'EMPTY')}).</div>
              ) : (
                <div className="max-h-[280px] overflow-auto space-y-2 font-mono text-[10px] text-slate-400">
                  <div className="text-slate-500">
                    workflow <span className="text-slate-300">{String((wf.workflow as { id?: string })?.id || '')}</span>{' '}
                    · {nodes.length} nodes · {edges.length} edges
                  </div>
                  <div className="space-y-0.5">
                    {edges.map((e, i) => (
                      <div key={i} className="truncate">
                        {String(e.from_node_key)} → {String(e.to_node_key)}{' '}
                        <span className="text-slate-600">{String(e.condition_type || '')}</span>
                      </div>
                    ))}
                  </div>
                </div>
              )}
            </Section>

            <Section title="Execution dependency graph" subtitle="agentsam_execution_dependency_graph">
              {depRows.length ? (
                <div className="max-h-[280px] overflow-auto font-mono text-[10px] text-slate-400 space-y-1">
                  {depRows.slice(0, 40).map((row, i) => (
                    <pre key={i} className="whitespace-pre-wrap break-all text-[10px] text-slate-500">
                      {JSON.stringify(row).slice(0, 280)}
                    </pre>
                  ))}
                </div>
              ) : (
                <div className="text-slate-500">No dependency rows in window.</div>
              )}
            </Section>
          </div>

          <div className="grid gap-3 lg:grid-cols-2">
            <Section title="Tool-call ledger" subtitle="agentsam_execution_steps (truncated previews)">
              <div className="max-h-[260px] overflow-auto">
                <table className="w-full border-collapse text-[10px]">
                  <thead>
                    <tr className="text-left text-slate-500">
                      <th className="pb-1 pr-2">node</th>
                      <th className="pb-1 pr-2">type</th>
                      <th className="pb-1 pr-2">status</th>
                      <th className="pb-1">ms</th>
                    </tr>
                  </thead>
                  <tbody>
                    {toolLedger.map((t) => (
                      <tr
                        key={String(t.step_id)}
                        className="cursor-pointer border-t border-slate-800/60 hover:bg-slate-900/40"
                        onClick={() => setInspector(t)}
                      >
                        <td className="py-1 pr-2 font-mono text-slate-300 truncate max-w-[140px]">{String(t.node_key)}</td>
                        <td className="py-1 pr-2 text-slate-500">{String(t.node_type || '—')}</td>
                        <td className="py-1 pr-2">{String(t.status)}</td>
                        <td className="py-1 text-slate-500">{String(t.latency_ms ?? '—')}</td>
                      </tr>
                    ))}
                  </tbody>
                </table>
                {!toolLedger.length ? <div className="text-slate-500">No steps for this run.</div> : null}
              </div>
            </Section>

            <Section title="Node inspector" subtitle="Click a ledger row">
              {!inspector ? (
                <div className="text-slate-500">No node selected.</div>
              ) : (
                <div className="max-h-[260px] overflow-auto font-mono text-[10px] text-slate-400 space-y-1">
                  <div>
                    <span className="text-slate-600">step_id</span> {String(inspector.step_id)}
                  </div>
                  <div>
                    <span className="text-slate-600">node_key</span> {String(inspector.node_key)}
                  </div>
                  <pre className="whitespace-pre-wrap break-all text-[10px] text-slate-500">
                    {String(inspector.preview || '—')}
                  </pre>
                </div>
              )}
            </Section>
          </div>
        </div>
      </div>
    </div>
  );
}

/**
 * Overview — remaster v2 (modular)
 * Inner Animal Media · Agent Sam Observability
 * Layout/typography use the same :root tokens as the rest of the dashboard.
 */

import { useState, useEffect, useCallback, useMemo } from "react";
import type { ActivityData, AgentActivity, DashboardBundle, DeployData, KpiDef, KpiStripData, WorkflowData } from "./types";
import { T, fmt, seedArr, dashboardBundleUrl } from "./constants";
import { Ico } from "./primitives";
import { KpiStrip } from "./panels/KpiStrip";
import { SpendChart } from "./panels/SpendChart";
import { WorkflowPanel } from "./panels/WorkflowPanel";
import { TopServices } from "./panels/TopServices";
import { BudgetCard } from "./panels/BudgetCard";
import { WorkflowRunsChart } from "./panels/WorkflowRunsChart";
import { ToolWaterfall } from "./panels/ToolWaterfall";
import { ErrorInbox } from "./panels/ErrorInbox";
import { TokensChart } from "./panels/TokensChart";
import { ModelLeaderboard } from "./panels/ModelLeaderboard";
import { CostLatency } from "./panels/CostLatency";
import { RoutingDecisions } from "./panels/RoutingDecisions";
import { RagHealth } from "./panels/RagHealth";
import { DeploymentsTimeline } from "./panels/DeploymentsTimeline";
import { SystemHealth } from "./panels/SystemHealth";
import { ActiveProjects } from "./panels/ActiveProjects";
import { QuickNav } from "./panels/QuickNav";

export default function OverviewPage() {
  const [kpi, setKpi] = useState<KpiStripData | null>(null);
  const [activity, setActivity] = useState<ActivityData | null>(null);
  const [agent, setAgent] = useState<AgentActivity | null>(null);
  const [wf, setWf] = useState<WorkflowData | null>(null);
  const [dep, setDep] = useState<DeployData | null>(null);
  const [bundle, setBundle] = useState<DashboardBundle | null>(null);
  const [loading, setLoading] = useState(true);
  const [ts, setTs] = useState(new Date());

  const load = useCallback(async () => {
    setLoading(true);
    try {
      const [k, a, ag, w, d, b] = await Promise.allSettled([
        fetch("/api/overview/kpi-strip").then((r) => r.json()),
        fetch("/api/overview/activity-strip").then((r) => r.json()),
        fetch("/api/overview/agent-activity").then((r) => r.json()),
        fetch("/api/overview/commands-workflows").then((r) => r.json()),
        fetch("/api/overview/deployments").then((r) => r.json()),
        fetch(dashboardBundleUrl()).then((r) => r.json()),
      ]);
      if (k.status === "fulfilled") setKpi(k.value);
      if (a.status === "fulfilled") setActivity(a.value);
      if (ag.status === "fulfilled") setAgent(ag.value);
      if (w.status === "fulfilled") setWf(w.value);
      if (d.status === "fulfilled") setDep(d.value);
      if (b.status === "fulfilled") setBundle(b.value as DashboardBundle);
    } finally {
      setLoading(false);
      setTs(new Date());
    }
  }, []);

  useEffect(() => {
    load();
  }, [load]);

  const cost = kpi?.cost_usd ?? 0;
  const calls = activity?.weekly_activity?.agent_calls ?? kpi?.api_calls ?? 0;
  const hrs = activity?.worked_this_week?.hours_this_week ?? 0;
  const mcp = kpi?.mcp_calls ?? 0;
  const top = activity?.projects?.top ?? [];

  const BK = bundle?.kpis;
  const liveKpi = bundle?.ok === true && BK != null;

  const monthlyBurn = liveKpi ? Number(BK.monthly_burn_usd) || 0 : cost || 37245;
  const agentCalls7 = liveKpi ? Number(BK.agent_calls_7d) || 0 : calls || 128900;
  const tokens7 = liveKpi ? Number(BK.tokens_7d) || 0 : 1_280_000;
  const mcpToday = liveKpi ? Number(BK.mcp_calls_today) || 0 : mcp || 5842;
  const hoursWeekDistinct = liveKpi ? Number(BK.hours_week_distinct) || 0 : Math.round(hrs || 24.6);
  const openTasksStr = liveKpi ? String(Number(BK.open_tasks) || 0) : "247";
  const healthRatio = BK?.worker_health_ratio;
  const healthPct =
    liveKpi && healthRatio != null && Number.isFinite(Number(healthRatio))
      ? `${Number(healthRatio).toFixed(1)}%`
      : liveKpi
        ? "—"
        : "95%";
  const push7dStr = liveKpi ? String(Number(BK.github_push_events_7d) || 0) : "42";
  const wfRunsToday = liveKpi ? String(Number(BK.workflow_runs_today_total) || 0) : "128";
  const wfRunsTodayCmp = liveKpi
    ? `OK ${Number(BK.workflow_runs_today_success) || 0} · fail ${Number(BK.workflow_runs_today_failed) || 0}`
    : "vs yesterday 112";

  const topSvcEvents = useMemo(() => {
    if (bundle?.top_services?.length) {
      return bundle.top_services.map((t) => ({
        type: String(t.tool_name || "tool"),
        count: Math.round(Number(t.total_calls) || 0),
      }));
    }
    return agent?.events ?? [];
  }, [bundle?.top_services, agent?.events]);

  const kpis: KpiDef[] = [
    { icon: Ico.flame, label: "Monthly Burn", value: fmt.usd(monthlyBurn), trend: liveKpi ? 0 : 12.4, compare: liveKpi ? "MTD · agentsam_usage_events" : `vs last 7d ${fmt.usd(monthlyBurn * 0.88)}`, spark: seedArr(monthlyBurn, 9), color: T.amber },
    { icon: Ico.zap, label: "Agent Calls", value: fmt.num(agentCalls7), trend: liveKpi ? 0 : 18.6, compare: liveKpi ? "Last 7d · usage_events" : `vs last 7d ${fmt.num(agentCalls7 * 0.84)}`, spark: seedArr(agentCalls7, 9), color: T.accent },
    { icon: Ico.cpu, label: "Tokens", value: fmt.tok(tokens7), trend: liveKpi ? 0 : 5.2, compare: liveKpi ? "7d · tokens_in + tokens_out" : "cached + live", spark: seedArr(Math.min(tokens7 / 1e3, 999_999), 9), color: T.blue },
    { icon: Ico.tool, label: "MCP Calls Today", value: fmt.num(mcpToday), trend: liveKpi ? 0 : 23.1, compare: liveKpi ? "agentsam_mcp_tool_execution" : `vs yesterday ${fmt.num(mcpToday * 0.81)}`, spark: seedArr(mcpToday, 9), color: T.accent },
    { icon: Ico.route, label: "Workflow Runs Today", value: wfRunsToday, trend: liveKpi ? 0 : 6.2, compare: liveKpi ? wfRunsTodayCmp : "agentsam_workflow_runs", spark: seedArr(Number(wfRunsToday) || 128, 9), color: T.violet },
    { icon: Ico.clock, label: "Hours This Week", value: fmt.num(hoursWeekDistinct), trend: liveKpi ? 0 : 14.2, compare: liveKpi ? "Distinct hour buckets" : `vs last week ${fmt.hrs((hrs || 24.6) * 0.88)}`, spark: seedArr(hoursWeekDistinct || 24, 9), color: T.green },
    { icon: Ico.list, label: "Open Tasks", value: openTasksStr, trend: liveKpi ? 0 : 9.8, compare: liveKpi ? "agentsam_plans Σ(tasks_total−done)" : "vs yesterday 225", spark: seedArr(Number(openTasksStr) || 247, 9), color: T.amber },
    { icon: Ico.pulse, label: "Worker Health", value: healthPct, trend: liveKpi ? 0 : -4.2, compare: liveKpi ? "Latest deployment_health / worker" : "vs last 7d 91%", spark: seedArr(liveKpi && healthRatio != null ? Number(healthRatio) : 95, 9), color: T.green },
    { icon: Ico.deploy, label: "GitHub Push", value: push7dStr, trend: liveKpi ? 0 : 8.0, compare: liveKpi ? "Webhook push · 7d" : "deploy feed", spark: seedArr(Number(push7dStr) || 42, 9), color: T.violet },
  ];

  const timeStr = ts.toLocaleTimeString("en-US", { hour: "2-digit", minute: "2-digit", second: "2-digit" });

  return (
    <>
      <style>{`
        @keyframes ovpulse{0%,100%{opacity:1}50%{opacity:0.4}}
        .ov-wrap *{box-sizing:border-box;}
        .ov-wrap a{color:var(--accent-secondary, var(--solar-cyan, #2dd4bf));}
      `}</style>
      <div className="ov-wrap" style={{ fontFamily: T.font, background: T.bg, color: T.text, minHeight: "100vh", padding: "22px 26px", overflowX: "hidden" }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: 20, flexWrap: "wrap", gap: 10 }}>
          <div>
            <div style={{ fontSize: 10, fontWeight: 600, letterSpacing: "0.12em", textTransform: "uppercase", color: T.muted, marginBottom: 4 }}>OPS OVERVIEW</div>
            <h1 style={{ margin: 0, fontSize: 24, fontWeight: 700, letterSpacing: "-0.02em" }}>Overview</h1>
            <p style={{ margin: "3px 0 0", fontSize: 11, color: T.muted }}>Live cost, health, and execution telemetry</p>
          </div>
          <div style={{ display: "flex", alignItems: "center", gap: 10, flexWrap: "wrap" }}>
            <span style={{ fontSize: 10, color: T.muted }}>Last refreshed: {timeStr}</span>
            <a href="/dashboard/analytics" style={{ fontSize: 10, textDecoration: "none" }}>
              Health dashboard →
            </a>
            <button
              onClick={load}
              style={{
                fontSize: 11,
                color: T.accent,
                background: "color-mix(in srgb, var(--accent-secondary, var(--solar-cyan)) 12%, transparent)",
                border: "1px solid color-mix(in srgb, var(--accent-secondary, var(--solar-cyan)) 28%, transparent)",
                borderRadius: 7,
                padding: "6px 14px",
                cursor: "pointer",
                fontFamily: T.font,
                display: "flex",
                alignItems: "center",
                gap: 6,
              }}
            >
              {Ico.refresh} Refresh
            </button>
          </div>
        </div>

        <QuickNav />

        <KpiStrip kpis={kpis} loading={loading} />

        <div style={{ display: "grid", gridTemplateColumns: "3fr 1.1fr 1.1fr 1.1fr", gap: 10, marginBottom: 10 }}>
          <SpendChart spendRows={bundle?.spend_by_day_provider} />
          <WorkflowPanel data={wf} workflowStats={bundle?.workflow_stats} />
          <TopServices events={topSvcEvents} />
          <BudgetCard cost={cost} budget={bundle?.budget} />
        </div>

        <div style={{ display: "flex", alignItems: "center", gap: 8, padding: "14px 0 12px", borderTop: `1px solid ${T.border}` }}>
          <span style={{ color: T.muted, display: "flex" }}>{Ico.pulse}</span>
          <span style={{ fontSize: 11, fontWeight: 700, letterSpacing: "0.08em", textTransform: "uppercase", color: T.muted }}>System Pulse / Execution Analytics</span>
        </div>

        <div style={{ display: "grid", gridTemplateColumns: "1.3fr 1.2fr 1.5fr 1.1fr", gap: 10, marginBottom: 10 }}>
          <WorkflowRunsChart workflowTimeseries={bundle?.workflow_timeseries} stackRows={bundle?.workflow_by_day_status} />
          <ToolWaterfall toolWaterfall={bundle?.tool_waterfall} />
          <ErrorInbox errorLog={bundle?.error_log} errorSeverityTimeseries={bundle?.error_severity_timeseries} />
          <TokensChart tokenTimeseries={bundle?.token_timeseries} />
        </div>

        <div style={{ display: "grid", gridTemplateColumns: "1.5fr 1fr 1fr", gap: 10, marginBottom: 10 }}>
          <ModelLeaderboard perfRows={bundle?.model_leaderboard} />
          <CostLatency costLatency={bundle?.cost_latency} />
          <RoutingDecisions arms={bundle?.routing_arms} routingTimeseries={bundle?.routing_timeseries} />
